const EXPORT_STORY_PHASE_START = 0;
const EXPORT_STORY_PHASE_WRAP_SPAN = Math.max(0.0001, 1 - EXPORT_STORY_PHASE_START);

(() => {
  const configNode = document.getElementById("working-3session-export-runtime-config");
  const config = configNode ? JSON.parse(configNode.textContent || "{}") : {};
  const values = config.values || {};
  const checked = config.checked || {};

  for (const [id, value] of Object.entries(values)) {
    const node = document.getElementById(id);
    if (!node) continue;
    if (!Object.prototype.hasOwnProperty.call(node, "value")) {
      Object.defineProperty(node, "value", {
        configurable: true,
        get() {
          return this.dataset.value || "";
        },
        set(nextValue) {
          this.dataset.value = String(nextValue);
        }
      });
    }
    if (!Object.prototype.hasOwnProperty.call(node, "checked")) {
      Object.defineProperty(node, "checked", {
        configurable: true,
        get() {
          return this.dataset.checked === "true";
        },
        set(nextValue) {
          this.dataset.checked = String(Boolean(nextValue));
        }
      });
    }
    node.value = value;
    node.checked = Boolean(checked[id]);
  }
})();

