    function clamp(value, min, max) {
      return Math.min(max, Math.max(min, value));
    }

    function smooth01(value) {
      const t = clamp(value, 0, 1);
      return t * t * (3 - 2 * t);
    }

    function circularPulse(phase, center, width) {
      const d = Math.abs(((phase - center + 0.5) % 1) - 0.5);
      return smooth01(clamp(1 - d / width, 0, 1));
    }

    function intervalHold(phase, start, end) {
      const inT = smooth01(clamp((phase - start) / 0.12, 0, 1));
      const outT = 1 - smooth01(clamp((phase - end) / 0.16, 0, 1));
      return inT * outT;
    }

    function lerp(a, b, t) {
      return a + (b - a) * t;
    }

    function storyMotionState() {
      const phase = ((Number(storyMotionPhase.value) % 1) + 1) % 1;
      const speed = Number(storyMotionSpeed.value);
      const time = phase * STORY_MOTION_LOOP_SECONDS;
      const range = (start, end) => smooth01(clamp((time - start) / (end - start), 0, 1));
      const window = (inStart, inEnd, outStart, outEnd) => range(inStart, inEnd) * (1 - range(outStart, outEnd));
      const pop = (start, end) => {
        const t = clamp((time - start) / (end - start), 0, 1);
        if (t <= 0) return 0;
        if (t < 0.58) return lerp(0.42, 1.14, smooth01(t / 0.58));
        return lerp(1.14, 1, smooth01((t - 0.58) / 0.42));
      };
      const codePop = pop(0.03, 0.48);
      const codeExit = range(2.58, 2.9);
      const codeHold = window(0.03, 0.18, 2.58, 3.02);
      const chatPop = pop(3.16, 3.7);
      const chatExit = range(5.38, 5.72);
      const chatHold = window(3.12, 3.55, 5.55, 5.9);
      const thinking = window(3.02, 3.35, 5.42, 5.78);
      const chatMessagePop = (start, duration = 0.36) => {
        const reveal = smooth01(clamp((time - start) / duration, 0, 1));
        return clamp(reveal + Math.sin(Math.PI * reveal) * 0.06, 0, 1);
      };
      const chatMessages = [
        chatMessagePop(3.62, 0.32),
        chatMessagePop(4.02, 0.32),
        chatMessagePop(4.42, 0.32),
        chatMessagePop(4.82, 0.32)
      ];
      const codeType = smooth01(clamp((time - 0.42) / 1.35, 0, 1));
      const focusMouth = window(0.42, 0.9, 2.48, 2.9);
      const thinkingMouthBreath = 0.5 + 0.5 * Math.sin(time * Math.PI * 1.35 - Math.PI / 2);
      const thinkingMouthInset = lerp(Number(mouthThinkingMin.value), Number(mouthThinkingMax.value), thinkingMouthBreath);
      const fishLookFace = range(STORY_FISH_LOOK_START_SECONDS, STORY_FISH_LOOK_START_SECONDS + 0.42);
      const firstBobberMotionTime = STORY_BITE_START_SECONDS
        + ((BITE_FIRST_PULSE_PHASE - 0.018 - BITE_SWIM_END_PHASE) / (1 - BITE_SWIM_END_PHASE))
          * (STORY_BITE_END_SECONDS - STORY_BITE_START_SECONDS);
      const wowStart = firstBobberMotionTime;
      const wowOpen = range(wowStart, wowStart + 0.16);
      const wowClose = range(wowStart + 0.34, wowStart + 0.68);
      const fishWow = clamp(wowOpen * (1 - wowClose), 0, 1);
      const fishWowPop = clamp(fishWow + Math.sin(Math.PI * wowOpen) * (1 - wowClose) * 0.04, 0, 1);
      const fishMouthPulse = fishWow * (0.5 + 0.5 * Math.sin(2 * Math.PI * (time - wowStart) / 0.74 - Math.PI / 2));
      let mouthInsetValue = lerp(0, Number(mouthFocusInset.value), focusMouth);
      mouthInsetValue = lerp(mouthInsetValue, thinkingMouthInset, thinking);
      mouthInsetValue = lerp(mouthInsetValue, Number(mouthHappyInset.value), fishLookFace);
      const mouthHappyOpenValue = Number(mouthHappyOpen.value) * fishWowPop;
      const browFocusValue = focusMouth * (1 - fishWow);
      const browThinkingValue = thinking * (1 - fishWow);
      const browHappyValue = fishWowPop;
      const command = window(0.86, 1.06, 2.48, 2.9);
      const commandWaveT = clamp((time - 0.86) / 1.36, 0, 1);
      const commandStops = [
        [0, -25.5],
        [0.13, 9.5],
        [0.24, 2.5],
        [0.39, -30],
        [0.52, 16],
        [0.65, 5.5],
        [0.80, -22],
        [0.92, 12.5],
        [1, -25.5]
      ];
      let commandRotate = commandStops[0][1];
      for (let i = 1; i < commandStops.length; i += 1) {
        const [nextT, nextRotate] = commandStops[i];
        const [prevT, prevRotate] = commandStops[i - 1];
        if (commandWaveT <= nextT) {
          commandRotate = lerp(prevRotate, nextRotate, smooth01(clamp((commandWaveT - prevT) / (nextT - prevT), 0, 1)));
          break;
        }
      }
      const handLift = range(0.1, 0.62);
      const handRaisedRotate = lerp(-42, 15.5, handLift);
      const handCommandRotate = lerp(handRaisedRotate, commandRotate, command);
      const handExitRotate = lerp(handCommandRotate, -55.5, codeExit);
      const handExitOpacity = clamp(1 - codeExit, 0, 1);
      const handBackHold = Math.max(1 - handLift, range(5.5, 5.84));
      const timelineLeftHandX = lerp(DEFAULT_LEFT_HAND_X - 5, DEFAULT_LEFT_HAND_X, handLift);
      const timelineLeftHandY = lerp(DEFAULT_LEFT_HAND_Y + 18, DEFAULT_LEFT_HAND_Y, handLift);
      const timelineLeftHandScale = lerp(0.94, DEFAULT_LEFT_HAND_SCALE, handLift);
      const timelineLeftHandRotate = handExitRotate;
      const timelineLeftHandOpacity = handLift * handExitOpacity;
      const fishingPropsInRaw = clamp((time - STORY_FISHING_PROPS_START_SECONDS) / (STORY_FISHING_PROPS_END_SECONDS - STORY_FISHING_PROPS_START_SECONDS), 0, 1);
      const fishingPropsIn = smooth01(fishingPropsInRaw);
      const fishingPropsExitRaw = clamp((time - STORY_FISHING_PROPS_EXIT_START_SECONDS) / (STORY_FISHING_PROPS_EXIT_END_SECONDS - STORY_FISHING_PROPS_EXIT_START_SECONDS), 0, 1);
      const fishingPropsExit = smooth01(fishingPropsExitRaw);
      const fishingProps = fishingPropsIn * (1 - fishingPropsExit);
      const loopReset = range(STORY_LOOP_RESET_START_SECONDS, STORY_LOOP_RESET_END_SECONDS);
      const rightIdleBack = lerp(1 - fishingPropsIn, 1, loopReset);
      const fishTerminalEntryScale = fishingPropsInRaw < 1
        ? lerp(0.72, 1, fishingPropsIn) + Math.sin(Math.PI * fishingPropsInRaw) * 0.16
        : 1;
      const fishTerminalExitScale = fishingPropsExitRaw > 0
        ? lerp(1, 0.72, fishingPropsExit) + Math.sin(Math.PI * fishingPropsExitRaw) * 0.12
        : 1;
      const fishTerminalPopScale = fishTerminalEntryScale * fishTerminalExitScale;
      const fishTerminalPopDy = (1 - fishingPropsIn) * 22 - Math.sin(Math.PI * fishingPropsInRaw) * 5
        + fishingPropsExit * 30 - Math.sin(Math.PI * fishingPropsExitRaw) * 10;
      const fishTerminalPopRotate = (1 - fishingPropsIn) * -4 + fishingPropsExit * 5;
      const preBite = clamp(time / STORY_BITE_START_SECONDS, 0, 1);
      const biteTravel = clamp((time - STORY_BITE_START_SECONDS) / (STORY_BITE_END_SECONDS - STORY_BITE_START_SECONDS), 0, 1);
      const bitePhase = time < STORY_BITE_START_SECONDS
        ? lerp(0, BITE_SWIM_END_PHASE, preBite)
        : lerp(BITE_SWIM_END_PHASE, 1, biteTravel);

      let headYawValue = -92 * range(0.005, 0.36);
      let headRotateValue = 1.5 * range(0.005, 0.36);
      let headXValue = -3 * range(0.005, 0.36);
      let headYValue = -3.5 * range(0.005, 0.36);
      let glassesYValue = 0;
      let glassesRotateValue = 0;
      headYawValue = lerp(headYawValue, 0, codeExit);
      headRotateValue = lerp(headRotateValue, 0, codeExit);
      headXValue = lerp(headXValue, 0, codeExit);
      headYValue = lerp(headYValue, 0, codeExit);
      const chatLook = range(3, 3.38);
      headYawValue = lerp(headYawValue, 59, chatLook);
      headRotateValue = lerp(headRotateValue, -8.5, chatLook);
      headXValue = lerp(headXValue, 0, chatLook);
      headYValue = lerp(headYValue, 0, chatLook);
      if (time >= STORY_FISH_LOOK_START_SECONDS) {
        const lookFish = smooth01(clamp((time - STORY_FISH_LOOK_START_SECONDS) / (STORY_FISH_LOOK_END_SECONDS - STORY_FISH_LOOK_START_SECONDS), 0, 1));
        headYawValue = lerp(headYawValue, 42, lookFish);
        headRotateValue = lerp(headRotateValue, -5.5, lookFish);
        headXValue = lerp(headXValue, 3.5, lookFish);
        headYValue = lerp(headYValue, 1.5, lookFish);
        glassesYValue = lerp(0, -1.5, lookFish);
        glassesRotateValue = 0;
      }
      headYawValue = lerp(headYawValue, 0, loopReset);
      headRotateValue = lerp(headRotateValue, 0, loopReset);
      headXValue = lerp(headXValue, 0, loopReset);
      headYValue = lerp(headYValue, 0, loopReset);
      glassesYValue = lerp(glassesYValue, 0, loopReset);
      glassesRotateValue = lerp(glassesRotateValue, 0, loopReset);
      mouthInsetValue = lerp(mouthInsetValue, 0, loopReset);

      return {
        phase,
        speed,
        time,
        stage: time < 2.98
          ? "code-terminal"
          : time < 5.9
            ? "chat-thinking"
            : loopReset > 0
              ? "loop-reset"
              : "fish-bite-reaction",
        headYaw: headYawValue,
        headRotate: headRotateValue,
        headX: headXValue,
        headY: headYValue,
        glassesY: glassesYValue,
        glassesRotate: glassesRotateValue,
        leftHand: {
          x: timelineLeftHandX,
          y: timelineLeftHandY,
          scale: timelineLeftHandScale,
          thickness: DEFAULT_LEFT_HAND_THICKNESS,
          rotate: timelineLeftHandRotate,
          elbowAngle: DEFAULT_LEFT_HAND_ELBOW_ANGLE,
          elbowOut: DEFAULT_LEFT_HAND_ELBOW_OUT,
          opacity: timelineLeftHandOpacity,
          idleBack: handBackHold
        },
        rightHand: {
          x: DEFAULT_RIGHT_HAND_X,
          y: DEFAULT_RIGHT_HAND_Y,
          scale: DEFAULT_RIGHT_HAND_SCALE,
          rotate: STORY_FISHING_HAND_ROTATE,
          opacity: fishingProps,
          idleBack: rightIdleBack
        },
        fishingGear: {
          opacity: fishingProps
        },
        fishTerminal: {
          opacity: fishingProps,
          popScale: fishTerminalPopScale,
          popDy: fishTerminalPopDy,
          popRotate: fishTerminalPopRotate,
          exit: fishingPropsExit,
          exitRaw: fishingPropsExitRaw
        },
        code: {
          opacity: clamp(codeHold * (1 - codeExit * 0.85), 0, 1),
          scale: codePop > 0 ? codePop * (1 - codeExit * 0.08) : 0,
          dy: lerp(20, -14, codePop) - codeExit * 18,
          contentReveal: codeType,
          contentOpacity: clamp(codeType * (1 - codeExit), 0, 1),
          contentDy: -32 * codeExit
        },
        chat: {
          opacity: clamp(chatHold * (1 - chatExit * 0.9), 0, 1),
          scale: chatPop > 0 ? chatPop * (1 - chatExit * 0.08) : 0,
          dy: lerp(18, 0, chatPop) - chatExit * 16,
          messages: chatMessages
        },
        mouth: {
          inset: clamp(mouthInsetValue, 0, 18),
          happyOpen: clamp(mouthHappyOpenValue, 0, 100),
          happyPulse: clamp(fishMouthPulse, 0, 1)
        },
        brow: {
          focus: clamp(browFocusValue, 0, 1),
          thinking: clamp(browThinkingValue, 0, 1),
          happy: clamp(browHappyValue, 0, 1)
        },
        thinking,
        bitePhase: clamp(bitePhase, 0, 1)
      };
    }

    function applyStoryMotionToInputs() {
      const story = storyMotionState();
      leftHandIdleBackVisible = story.leftHand.idleBack || 0;
      rightHandIdleBackVisible = story.rightHand.idleBack || 0;
      headYaw.value = fmt(story.headYaw);
      headRotate.value = fmt(story.headRotate);
      headX.value = fmt(story.headX);
      headY.value = fmt(story.headY);
      glassesY.value = fmt(story.glassesY);
      glassesRotate.value = fmt(story.glassesRotate);
      leftHandX.value = fmt(story.leftHand.x);
      leftHandY.value = fmt(story.leftHand.y);
      leftHandScale.value = fmt(story.leftHand.scale);
      leftHandThickness.value = fmt(story.leftHand.thickness);
      leftHandRotate.value = fmt(story.leftHand.rotate);
      leftHandElbowAngle.value = fmt(story.leftHand.elbowAngle);
      leftHandElbowOut.value = fmt(story.leftHand.elbowOut);
      leftHandOpacity.value = fmt(story.leftHand.opacity);
      rightHandX.value = fmt(story.rightHand.x);
      rightHandY.value = fmt(story.rightHand.y);
      rightHandScale.value = fmt(story.rightHand.scale);
      rightHandRotate.value = fmt(story.rightHand.rotate);
      rightHandOpacity.value = fmt(story.rightHand.opacity);
      fishingGearOpacity.value = fmt(story.fishingGear.opacity);
      fishTerminalOpacity.value = fmt(story.fishTerminal.opacity);
      if (Number(thinkingHandOpacity.value) <= 0.01) {
        thinkingHandOpacity.value = DEFAULT_THINKING_HAND_OPACITY;
      }
      fishTerminalStoryScale = story.fishTerminal.popScale || 1;
      fishTerminalStoryDy = story.fishTerminal.popDy || 0;
      fishTerminalStoryRotate = story.fishTerminal.popRotate || 0;
      fishTerminalStoryExit = story.fishTerminal.exit || 0;
      fishTerminalStoryExitRaw = story.fishTerminal.exitRaw || 0;
      biteMotionPhase.value = fmtScale(story.bitePhase);
      fishTerminalPhase.value = fmtScale((story.time / FISH_TERMINAL_LOOP_SECONDS) % 1);
      rodMotionPhase.value = fmtScale((story.time / ROD_MOTION_LOOP_SECONDS) % 1);
    }

    function applyStoryKeyframePreset(frameName) {
      const preset = STORY_KEYFRAME_PRESETS[frameName];
      if (!preset) return;
      resetRightHandToDefaults();
      leftHandIdleBackVisible = 0;
      rightHandIdleBackVisible = 0;
      fishTerminalStoryScale = 1;
      fishTerminalStoryDy = 0;
      fishTerminalStoryRotate = 0;
      fishTerminalStoryExit = 0;
      fishTerminalStoryExitRaw = 0;
      if (preset.storyPhase != null) storyMotionPhase.value = fmtScale(preset.storyPhase);
      if (preset.storySpeed != null) storyMotionSpeed.value = preset.storySpeed;
      if (preset.headYaw != null) headYaw.value = preset.headYaw;
      if (preset.headX != null) headX.value = preset.headX;
      if (preset.headY != null) headY.value = preset.headY;
      if (preset.headRotate != null) headRotate.value = preset.headRotate;
      if (preset.eyesOpen != null) eyesOpen.value = preset.eyesOpen;
      if (preset.glassesY != null) glassesY.value = preset.glassesY;
      if (preset.glassesRotate != null) glassesRotate.value = preset.glassesRotate;
      if (preset.leftHandX != null) leftHandX.value = preset.leftHandX;
      if (preset.leftHandY != null) leftHandY.value = preset.leftHandY;
      if (preset.leftHandScale != null) leftHandScale.value = preset.leftHandScale;
      if (preset.leftHandThickness != null) leftHandThickness.value = preset.leftHandThickness;
      if (preset.leftHandRotate != null) leftHandRotate.value = preset.leftHandRotate;
      if (preset.leftHandElbowAngle != null) leftHandElbowAngle.value = preset.leftHandElbowAngle;
      if (preset.leftHandElbowOut != null) leftHandElbowOut.value = preset.leftHandElbowOut;
      if (preset.leftHandOpacity != null) leftHandOpacity.value = preset.leftHandOpacity;
      if (preset.leftHandIdleBack != null) leftHandIdleBackVisible = clamp(Number(preset.leftHandIdleBack), 0, 1);
      if (preset.rightHandIdleBack != null) rightHandIdleBackVisible = clamp(Number(preset.rightHandIdleBack), 0, 1);
      if (preset.thinkingHandX != null) thinkingHandX.value = preset.thinkingHandX;
      if (preset.thinkingHandY != null) thinkingHandY.value = preset.thinkingHandY;
      if (preset.thinkingHandScale != null) thinkingHandScale.value = preset.thinkingHandScale;
      if (preset.thinkingHandRotate != null) thinkingHandRotate.value = preset.thinkingHandRotate;
      if (preset.thinkingHandOpacity != null) thinkingHandOpacity.value = preset.thinkingHandOpacity;
      if (preset.rightHandX != null) rightHandX.value = preset.rightHandX;
      if (preset.rightHandY != null) rightHandY.value = preset.rightHandY;
      if (preset.rightHandScale != null) rightHandScale.value = preset.rightHandScale;
      if (preset.rightHandRotate != null) rightHandRotate.value = preset.rightHandRotate;
      if (preset.rightHandOpacity != null) rightHandOpacity.value = preset.rightHandOpacity;
      if (preset.fishingGearOpacity != null) fishingGearOpacity.value = preset.fishingGearOpacity;
      if (preset.fishTerminalOpacity != null) fishTerminalOpacity.value = preset.fishTerminalOpacity;
    }

    function updateKeyframeSelection() {
      storyKeyframeButtons.forEach((button) => {
        button.classList.toggle("is-active", button.dataset.frame === activeStoryKeyframeName);
      });
      if (storyKeyframeOut) storyKeyframeOut.textContent = activeStoryKeyframeName;
    }

    function selectStoryKeyframe(button) {
      activeStoryKeyframeName = button.dataset.frame || "自定义相位";
      storyMotionPhase.value = button.dataset.phase || "0";
      setStoryMotionPlaying(false);
      setFishTerminalPlaying(false);
      setRodMotionPlaying(false);
      setBiteMotionPlaying(false);
      applyStoryMotionToInputs();
      applyStoryKeyframePreset(activeStoryKeyframeName);
      updateKeyframeSelection();
      updateAll();
    }

    function fmt(value) {
      const rounded = Math.round(value * 1000) / 1000;
      return rounded.toFixed(3).replace(/\.?0+$/, "");
    }

    function fmtScale(value) {
      const rounded = Math.round(value * 10000) / 10000;
      return rounded.toFixed(4).replace(/\.?0+$/, "");
    }

    function numbers(value) {
      return (value.match(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi) || []).map(Number);
    }

    function interpolateNumberString(from, to, t) {
      const a = numbers(from);
      const b = numbers(to);
      let index = 0;
      if (!from || !to || a.length !== b.length) return t < 1 ? from : to;
      return from.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(lerp(a[index], b[index++] ?? a[index - 1], t)));
    }

    function axisT(value) {
      return smooth01(Math.abs(value) / 100);
    }

    function mixPoint(a, b, t) {
      return { x: lerp(a.x, b.x, t), y: lerp(a.y, b.y, t) };
    }

    function translate(x, y) {
      return Math.abs(x) < 1e-6 && Math.abs(y) < 1e-6 ? "" : `translate(${fmt(x)} ${fmt(y)})`;
    }

    function centeredTransform(origin, dx, dy, sx = 1, sy = 1) {
      if (Math.abs(dx) < 1e-6 && Math.abs(dy) < 1e-6 && Math.abs(sx - 1) < 1e-6 && Math.abs(sy - 1) < 1e-6) return "";
      return `translate(${fmt(origin.x + dx)} ${fmt(origin.y + dy)}) scale(${fmt(sx)} ${fmt(sy)}) translate(${fmt(-origin.x)} ${fmt(-origin.y)})`;
    }

    function transformPathPairs(path, fn) {
      const values = numbers(path);
      const output = [];
      for (let i = 0; i < values.length; i += 2) {
        const point = fn({ x: values[i], y: values[i + 1] });
        output.push(point.x, point.y);
      }
      let index = 0;
      return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(output[index++]));
    }

    function transformTopPoint(point, dir) {
      const axisX = dir < 0 ? 125 : 249;
      const axisTravel = (axisX - 374 / 2) * 0.75;
      const localX = point.x - axisX;
      const next = { x: axisTravel + axisX + localX, y: point.y };
      const weightT = clamp((point.x - RAW_ANCHORS.A.x) / (RAW_ANCHORS.G.x - RAW_ANCHORS.A.x), 0, 1);
      const weight = Math.pow(Math.sin(Math.PI * weightT), 0.9);
      return {
        x: point.x + (next.x - point.x) * weight,
        y: point.y
      };
    }

    function catmullPath(points, tension = 0.72, sharpness = 0.34) {
      const segs = [`M${fmt(points[0].x)} ${fmt(points[0].y)}`];
      for (let i = 0; i < points.length - 1; i += 1) {
        const p0 = points[Math.max(0, i - 1)];
        const p1 = points[i];
        const p2 = points[i + 1];
        const p3 = points[Math.min(points.length - 1, i + 2)];
        const nearBridge = ["C", "D", "E"].includes(p1.id) || ["C", "D", "E"].includes(p2.id);
        const localTension = tension * (nearBridge ? (1 - sharpness * 0.42) : 1);
        const c1 = {
          x: p1.x + (p2.x - p0.x) * localTension / 6,
          y: p1.y + (p2.y - p0.y) * localTension / 6
        };
        const c2 = {
          x: p2.x - (p3.x - p1.x) * localTension / 6,
          y: p2.y - (p3.y - p1.y) * localTension / 6
        };
        segs.push(`C${fmt(c1.x)} ${fmt(c1.y)} ${fmt(c2.x)} ${fmt(c2.y)} ${fmt(p2.x)} ${fmt(p2.y)}`);
      }
      return segs.join(" ");
    }

    function yawFacePath(yaw) {
      const dir = Math.sign(yaw);
      const t = axisT(yaw);
      if (!dir || t <= 0.001) return NEUTRAL_CHEEK_PATH;
      const top = TOP_CHAIN.map((id) => {
        const start = RAW_ANCHORS[id];
        const end = transformTopPoint(start, dir);
        return { id, ...mixPoint(start, end, t) };
      });
      const sideTail = dir < 0 ? LEFT_TAIL : RIGHT_TAIL;
      const tail = FRONT_TAIL.map((seg, index) => {
        const mixed = seg.map((value, numberIndex) => lerp(value, sideTail[index][numberIndex], t));
        return `C${fmt(mixed[0])} ${fmt(mixed[1])} ${fmt(mixed[2])} ${fmt(mixed[3])} ${fmt(mixed[4])} ${fmt(mixed[5])}`;
      }).join(" ");
      return `${catmullPath(top)} ${tail}Z`;
    }

    function yawHeadCapPath(yaw) {
      const yawT = axisT(yaw);
      const dir = Math.sign(yaw);
      const yawTarget = dir > 0 ? RIGHT_HEAD_CAP_PATH : LEFT_HEAD_CAP_PATH;
      return dir ? interpolateNumberString(NEUTRAL_HEAD_CAP_PATH, yawTarget, yawT) : NEUTRAL_HEAD_CAP_PATH;
    }

    function yawCreasePath(side, yaw) {
      const isLeft = side === "left";
      const base = isLeft ? NEUTRAL_LEFT_CREASE_PATH : NEUTRAL_RIGHT_CREASE_PATH;
      const startX = isLeft ? 62 : 312;
      const baseLength = 38;
      const yawT = axisT(yaw);
      const yawPull = Math.sign(yaw) * yawT;
      return transformPathPairs(base, (point) => {
        const along = isLeft
          ? clamp((point.x - 62) / baseLength, 0, 1)
          : clamp((312 - point.x) / baseLength, 0, 1);
        return {
          x: point.x + yawPull * (isLeft ? 1 : -1) * lerp(3, 6, along),
          y: point.y
        };
      });
    }

    function facePlaneTransform(yaw) {
      const dir = Math.sign(yaw);
      const yawT = axisT(yaw);
      const axis = 187 + dir * 62 * yawT;
      const dx = dir * 46.5 * yawT;
      if (!dir || yawT <= 0.001) return "";
      return `translate(${fmt(dx)} 0) translate(${fmt(axis)} 172) skewX(0) scale(1 1) translate(${fmt(-axis)} -172)`;
    }

    function elementOffsets(yaw) {
      const dir = Math.sign(yaw);
      const yawT = axisT(yaw);
      const leftBlushYaw = dir < 0
        ? { dx: 6.5 * yawT, dy: 0, sx: 1, sy: 1 }
        : { dx: -24 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) };
      const rightBlushYaw = dir < 0
        ? { dx: 25 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) }
        : { dx: -5.5 * yawT, dy: 0, sx: 1, sy: 1 };
      return {
        leftEye: { dx: dir < 0 ? -2 * yawT : 0, dy: 0 },
        rightEye: { dx: dir > 0 ? 2 * yawT : 0, dy: 0 },
        leftBlush: leftBlushYaw,
        rightBlush: rightBlushYaw
      };
    }

    function earState(yaw) {
      const dir = Math.sign(yaw);
      const yawT = axisT(yaw);
      const left = { x: 0, y: 0, grow: 0 };
      const right = { x: 0, y: 0, grow: 0 };
      if (dir < 0) {
        left.x += -3.5 * yawT;
        left.y += 3.5 * yawT;
        right.grow = smooth01(clamp((yawT - 0.12) / 0.88, 0, 1));
      } else if (dir > 0) {
        right.x += -9.5 * yawT;
        right.y += 3.5 * yawT;
        left.grow = smooth01(clamp((yawT - 0.12) / 0.88, 0, 1));
      }
      return { left, right };
    }

    function tuftLookTransform(yaw) {
      const dir = Math.sign(yaw);
      const yawT = axisT(yaw);
      const yawDx = dir < 0 ? -21.7 * yawT : dir > 0 ? -10.3 * yawT : 0;
      return translate(yawDx, 0);
    }

    function buildLowerBodyPath(leftBulgeValue, widthValue, dropValue) {
      const w = Number(widthValue);
      const drop = Number(dropValue);
      const side = smooth01(BODY_SIDE_ROUND);
      const bottom = smooth01(BODY_BOTTOM_ROUND);
      const leftBulgeAmount = Number(leftBulgeValue);
      const bottomY = 412 + drop;
      const leftSideX = 60 - leftBulgeAmount;
      const leftUpperHandleX = 60 - leftBulgeAmount * 0.52;
      const leftBottomX = 101 - w;
      const rightBottomX = 273 + w;
      const leftSidePull = 60 - w * lerp(0.12, 0.34, side) - leftBulgeAmount * 0.42;
      const rightSidePull = 314 + w * lerp(0.12, 0.34, side);
      const leftBottomPull = leftBottomX - w * lerp(0.04, 0.16, bottom);
      const rightBottomPull = rightBottomX + w * lerp(0.04, 0.16, bottom);
      const sideHandleY = 380 + drop * 0.18;
      const bottomHandleY = bottomY + drop * 0.05;
      return [
        "M187 200",
        `C113 200 ${fmt(leftUpperHandleX)} 251 ${fmt(leftSideX)} 322`,
        `C${fmt(leftSidePull)} ${fmt(sideHandleY)} ${fmt(leftBottomPull)} ${fmt(bottomHandleY)} 187 ${fmt(bottomY)}`,
        `C${fmt(rightBottomPull)} ${fmt(bottomHandleY)} ${fmt(rightSidePull)} ${fmt(sideHandleY)} 314 322`,
        "C314 251 261 200 187 200Z"
      ].join(" ");
    }

    function updateBody() {
      const leftBulgeValue = Number(leftBulge.value);
      const widthValue = Number(bodyWidth.value);
      const dropValue = Number(bottomDrop.value);
      const d = buildLowerBodyPath(leftBulgeValue, widthValue, dropValue);
      if (body) {
        body.setAttribute("d", d);
        body.setAttribute("data-draft-left-bulge", String(leftBulgeValue));
      }
      leftBulgeOut.textContent = fmt(leftBulgeValue);
      bodyWidthOut.textContent = fmt(widthValue);
      bottomDropOut.textContent = fmt(dropValue);
      return d;
    }

    function applyMouthInset(node, baseD, inset) {
      if (!node) return;
      node.setAttribute("d", baseD);
      node.removeAttribute("clip-path");
      node.setAttribute("stroke-linecap", "round");
      node.setAttribute("stroke-linejoin", "round");
      const amount = clamp(inset, 0, 18);
      if (amount <= 0.05 || !node.getTotalLength) {
        node.removeAttribute("stroke-dasharray");
        node.removeAttribute("stroke-dashoffset");
        node.removeAttribute("data-mouth-inset");
        return;
      }
      const length = node.getTotalLength();
      const visibleLength = Math.max(0.1, length - amount);
      node.setAttribute("stroke-dasharray", `${fmt(visibleLength)} ${fmt(length + 24)}`);
      node.setAttribute("stroke-dashoffset", "0");
      node.setAttribute("data-mouth-inset", fmt(amount));
    }

    function happyMouthParams(pulseT) {
      const pulse = clamp(pulseT, 0, 1) * Number(mouthHappyPulse.value);
      return {
        sideY: HAPPY_MOUTH.sideY,
        bottomY: HAPPY_MOUTH.bottomY + HAPPY_MOUTH.bottomPulse * pulse,
        halfW: HAPPY_MOUTH.halfW + HAPPY_MOUTH.halfPulse * pulse,
        doorInset: HAPPY_MOUTH.doorInset - HAPPY_MOUTH.insetPulse * pulse,
        doorRound: HAPPY_MOUTH.doorRound + HAPPY_MOUTH.roundPulse * pulse
      };
    }

    function happyMouthOpeningClipD(progress, pulseT) {
      const p = clamp(progress / 100, 0, 1);
      const cx = HAPPY_MOUTH.cx;
      const mouth = happyMouthParams(pulseT);
      const sideY = mouth.sideY;
      if (p <= 0.01) {
        return [
          `M ${fmt(cx - 0.35)} ${fmt(sideY)}`,
          `C ${fmt(cx - 0.35)} ${fmt(sideY)} ${fmt(cx - 0.15)} ${fmt(sideY)} ${fmt(cx)} ${fmt(sideY)}`,
          `C ${fmt(cx + 0.15)} ${fmt(sideY)} ${fmt(cx + 0.35)} ${fmt(sideY)} ${fmt(cx + 0.35)} ${fmt(sideY)}`,
          `C ${fmt(cx + 0.35)} ${fmt(sideY + 0.15)} ${fmt(cx + 0.18)} ${fmt(sideY + 0.2)} ${fmt(cx)} ${fmt(sideY + 0.2)}`,
          `C ${fmt(cx - 0.18)} ${fmt(sideY + 0.2)} ${fmt(cx - 0.35)} ${fmt(sideY + 0.15)} ${fmt(cx - 0.35)} ${fmt(sideY)} Z`
        ].join(" ");
      }
      const dx = cx - 187;
      const topYShift = (sideY - 199) * 0.18;
      const tx = (value) => value + dx;
      const ty = (value) => value + topYShift;
      const fullBottomDrop = Math.max(0.15, mouth.bottomY - sideY);
      const bottomDrop = fullBottomDrop * p;
      const bottomY = sideY + bottomDrop;
      const bottomW = Math.max(6, mouth.halfW);
      return [
        `M ${fmt(tx(163))} ${fmt(ty(192))}`,
        `C ${fmt(tx(163))} ${fmt(ty(195))} ${fmt(tx(166))} ${fmt(ty(198))} ${fmt(tx(171))} ${fmt(ty(198))}`,
        `C ${fmt(tx(180))} ${fmt(ty(198))} ${fmt(tx(187))} ${fmt(ty(190))} ${fmt(tx(187))} ${fmt(ty(177))}`,
        `C ${fmt(tx(187))} ${fmt(ty(190))} ${fmt(tx(194))} ${fmt(ty(198))} ${fmt(tx(203))} ${fmt(ty(198))}`,
        `C ${fmt(tx(208))} ${fmt(ty(198))} ${fmt(tx(211))} ${fmt(ty(195))} ${fmt(tx(211))} ${fmt(ty(192))}`,
        `C ${fmt(tx(211))} ${fmt(bottomY - bottomDrop * 0.15)} ${fmt(cx + bottomW)} ${fmt(bottomY)} ${fmt(cx)} ${fmt(bottomY)}`,
        `C ${fmt(cx - bottomW)} ${fmt(bottomY)} ${fmt(tx(163))} ${fmt(bottomY - bottomDrop * 0.15)} ${fmt(tx(163))} ${fmt(ty(192))} Z`
      ].join(" ");
    }

    function happyMouthDoorClipD(pulseT) {
      const mouth = happyMouthParams(pulseT);
      const inset = clamp(mouth.doorInset, 0, 22);
      const cx = HAPPY_MOUTH.cx;
      const topY = 166;
      const tailY = 292;
      const sideY = mouth.sideY;
      const bottomY = mouth.bottomY;
      const left = 163 + inset;
      const right = 211 - inset;
      const lowerLeft = Math.max(left, cx - Math.max(0.1, mouth.halfW));
      const lowerRight = Math.min(right, cx + Math.max(0.1, mouth.halfW));
      const round = clamp(mouth.doorRound || 0, 0, Math.max(0.1, bottomY - sideY));
      const curveStartY = clamp(bottomY - round, sideY, bottomY - 0.1);
      const sideHandleY = lerp(curveStartY, bottomY, 0.72);
      const bottomHandleY = bottomY - round * 0.15;
      if (round <= 0.01) {
        return [
          `M ${fmt(left)} ${fmt(topY)}`,
          `L ${fmt(right)} ${fmt(topY)}`,
          `L ${fmt(right)} ${fmt(tailY)}`,
          `L ${fmt(left)} ${fmt(tailY)} Z`
        ].join(" ");
      }
      return [
        `M ${fmt(left)} ${fmt(topY)}`,
        `L ${fmt(right)} ${fmt(topY)}`,
        `L ${fmt(right)} ${fmt(curveStartY)}`,
        `C ${fmt(right)} ${fmt(sideHandleY)} ${fmt(lowerRight)} ${fmt(bottomHandleY)} ${fmt(lowerRight)} ${fmt(bottomY)}`,
        `L ${fmt(lowerRight)} ${fmt(tailY)}`,
        `L ${fmt(lowerLeft)} ${fmt(tailY)}`,
        `L ${fmt(lowerLeft)} ${fmt(bottomY)}`,
        `C ${fmt(lowerLeft)} ${fmt(bottomHandleY)} ${fmt(left)} ${fmt(sideHandleY)} ${fmt(left)} ${fmt(curveStartY)}`,
        `L ${fmt(left)} ${fmt(topY)} Z`
      ].join(" ");
    }

    function happyMouthCavityD() {
      const cx = HAPPY_MOUTH.cx;
      const cy = HAPPY_MOUTH.cavityY;
      const w = HAPPY_MOUTH.cavityW;
      const h = HAPPY_MOUTH.cavityH;
      return [
        `M ${fmt(cx - w)} ${fmt(cy)}`,
        `C ${fmt(cx - w)} ${fmt(cy - h * 0.55)} ${fmt(cx + w)} ${fmt(cy - h * 0.55)} ${fmt(cx + w)} ${fmt(cy)}`,
        `C ${fmt(cx + w)} ${fmt(cy + h * 0.66)} ${fmt(cx - w)} ${fmt(cy + h * 0.66)} ${fmt(cx - w)} ${fmt(cy)} Z`
      ].join(" ");
    }

    function happyMouthLowerCavityD(progress) {
      const p = clamp((progress - 18) / 82, 0, 1);
      const cx = HAPPY_MOUTH.cx;
      const cy = HAPPY_MOUTH.lowerCavityY;
      const w = Math.max(0.1, HAPPY_MOUTH.lowerCavityW * p);
      const h = Math.max(0.1, HAPPY_MOUTH.lowerCavityH * p);
      const tail = 46 + Math.max(0.15, HAPPY_MOUTH.bottomY - HAPPY_MOUTH.sideY);
      return [
        `M ${fmt(cx - w)} ${fmt(cy)}`,
        `C ${fmt(cx - w * 0.82)} ${fmt(cy - h)} ${fmt(cx + w * 0.82)} ${fmt(cy - h)} ${fmt(cx + w)} ${fmt(cy)}`,
        `L ${fmt(cx + w * 1.28)} ${fmt(cy + tail)}`,
        `L ${fmt(cx - w * 1.28)} ${fmt(cy + tail)} Z`
      ].join(" ");
    }

    function applyHappyMouthPose(progress, pulseT) {
      const amount = clamp(progress, 0, 100);
      const active = amount > 1;
      if (mouthOpeningClipPath) mouthOpeningClipPath.setAttribute("d", happyMouthOpeningClipD(amount, pulseT));
      if (mouthDoorClipPath) mouthDoorClipPath.setAttribute("d", happyMouthDoorClipD(pulseT));
      if (mouthInnerShade) mouthInnerShade.setAttribute("d", happyMouthCavityD());
      if (mouthCavityFill) mouthCavityFill.setAttribute("d", happyMouthCavityD());
      if (mouthLowerCavityFill) mouthLowerCavityFill.setAttribute("d", happyMouthLowerCavityD(amount));
      if (mouthInterior) {
        mouthInterior.style.display = active ? "" : "none";
        if (active) mouthInterior.removeAttribute("display");
        else mouthInterior.setAttribute("display", "none");
        mouthInterior.setAttribute("opacity", fmt(active ? 0.72 + 0.28 * clamp(amount / 100, 0, 1) : 0));
      }
      if (mouthLowerCavityFill) {
        mouthLowerCavityFill.style.display = amount > 18 ? "" : "none";
        if (amount > 18) mouthLowerCavityFill.removeAttribute("display");
        else mouthLowerCavityFill.setAttribute("display", "none");
      }
    }

    function browTransform(dy, rotate, cx, cy) {
      const parts = [];
      if (Math.abs(dy) > 0.02) parts.push(`translate(0 ${fmt(dy)})`);
      if (Math.abs(rotate) > 0.02) parts.push(`rotate(${fmt(rotate)} ${fmt(cx)} ${fmt(cy)})`);
      return parts.join(" ");
    }

    function updateBrows(story) {
      const focus = clamp(story?.brow?.focus ?? 0, 0, 1);
      const thinkingValue = clamp(story?.brow?.thinking ?? 0, 0, 1);
      const happy = clamp(story?.brow?.happy ?? 0, 0, 1);
      const serious = clamp(focus * (Number(browFocusDrop.value) / DEFAULT_BROW_FOCUS_DROP) * (1 - happy), 0, 1);
      const thinkTilt = Number(browThinkTilt.value) * thinkingValue * (1 - happy);
      const happyLift = Number(browHappyLift.value) * happy;
      const happyBounce = Number(browHappyBounce.value) * Math.sin(Math.PI * happy);
      const groupDy = -(happyLift + happyBounce);
      const leftDy = -thinkTilt * 0.45;
      const rightDy = thinkTilt * 0.25;
      const leftRotate = -thinkTilt * 0.22;
      const rightRotate = -thinkTilt * 0.18;
      const leftBrowD = interpolateNumberString(DEFAULT_LEFT_BROW_D, NOTIFICATION_SERIOUS_LEFT_BROW_D, serious);
      const rightBrowD = interpolateNumberString(DEFAULT_RIGHT_BROW_D, NOTIFICATION_SERIOUS_RIGHT_BROW_D, serious);

      if (brows) brows.setAttribute("transform", Math.abs(groupDy) > 0.02 ? `translate(0 ${fmt(groupDy)})` : "");
      if (leftBrow) {
        leftBrow.setAttribute("d", leftBrowD);
        leftBrow.setAttribute("data-serious-brow", fmt(serious));
        leftBrow.setAttribute("transform", browTransform(leftDy, leftRotate, 140, 116));
      }
      if (rightBrow) {
        rightBrow.setAttribute("d", rightBrowD);
        rightBrow.setAttribute("data-serious-brow", fmt(serious));
        rightBrow.setAttribute("transform", browTransform(rightDy, rightRotate, 234, 116));
      }

      return { focus, serious, thinking: thinkingValue, happy, groupDy, leftDy, rightDy };
    }

    function updateHeadFace(story) {
      const x = Number(headX.value);
      const y = Number(headY.value);
      const rotate = Number(headRotate.value);
      const yaw = Number(headYaw.value);
      const open = clamp(Number(eyesOpen.value), 0, 1);
      const glassesOffsetY = Number(glassesY.value);
      const glassesAngle = Number(glassesRotate.value);
      const mouthInsetValue = clamp(story?.mouth?.inset ?? 0, 0, 18);
      const mouthHappyOpenValue = clamp(story?.mouth?.happyOpen ?? 0, 0, 100);
      const mouthHappyPulseValue = clamp(story?.mouth?.happyPulse ?? 0, 0, 1);
      const lookActive = Math.abs(yaw) > 0.001;
      const cheekPath = yawFacePath(yaw);
      const faceTransform = lookActive ? facePlaneTransform(yaw) : "";
      const offsets = elementOffsets(yaw);
      const ears = earState(yaw);

      if (headPose) headPose.setAttribute("transform", `translate(${fmt(x)} ${fmt(y)}) rotate(${fmt(rotate)} 187 244)`);
      if (headCap) headCap.setAttribute("d", yawHeadCapPath(yaw));
      if (cheek) cheek.setAttribute("d", cheekPath);
      if (blushClip) blushClip.setAttribute("d", cheekPath);
      if (leftCheekCrease) {
        leftCheekCrease.setAttribute("d", yawCreasePath("left", yaw));
        leftCheekCrease.setAttribute("stroke-width", lookActive ? "2.6" : "3");
      }
      if (rightCheekCrease) {
        rightCheekCrease.setAttribute("d", yawCreasePath("right", yaw));
        rightCheekCrease.setAttribute("stroke-width", lookActive ? "2.6" : "3");
      }
      if (faceLayer) faceLayer.setAttribute("transform", faceTransform || "translate(0 0)");
      if (blushTransform) blushTransform.setAttribute("transform", faceTransform || "translate(0 0)");
      if (headTufts) headTufts.setAttribute("transform", lookActive ? tuftLookTransform(yaw) : "");
      if (leftEar) leftEar.setAttribute("transform", lookActive ? translate(ears.left.x, ears.left.y) : "");
      if (rightEar) rightEar.setAttribute("transform", lookActive ? translate(ears.right.x, ears.right.y) : "");
      if (leftEarOuter) leftEarOuter.setAttribute("r", fmt(lerp(34, 37.4, ears.left.grow)));
      if (leftEarInner) leftEarInner.setAttribute("r", fmt(lerp(18, 19.8, ears.left.grow)));
      if (rightEarOuter) rightEarOuter.setAttribute("r", fmt(lerp(34, 37.4, ears.right.grow)));
      if (rightEarInner) rightEarInner.setAttribute("r", fmt(lerp(18, 19.8, ears.right.grow)));
      if (leftEye) leftEye.setAttribute("opacity", fmt(open));
      if (rightEye) rightEye.setAttribute("opacity", fmt(open));
      if (leftEye) leftEye.setAttribute("transform", centeredTransform({ x: 138, y: 157 }, offsets.leftEye.dx, offsets.leftEye.dy));
      if (rightEye) rightEye.setAttribute("transform", centeredTransform({ x: 237, y: 157 }, offsets.rightEye.dx, offsets.rightEye.dy));
      const leftBlush = document.getElementById("left-blush");
      const rightBlush = document.getElementById("right-blush");
      if (leftBlush) leftBlush.setAttribute("transform", centeredTransform({ x: 92, y: 185 }, offsets.leftBlush.dx, offsets.leftBlush.dy, offsets.leftBlush.sx, offsets.leftBlush.sy));
      if (rightBlush) rightBlush.setAttribute("transform", centeredTransform({ x: 281, y: 185 }, offsets.rightBlush.dx, offsets.rightBlush.dy, offsets.rightBlush.sx, offsets.rightBlush.sy));
      if (leftEyeArc) leftEyeArc.setAttribute("opacity", fmt(1 - open));
      if (rightEyeArc) rightEyeArc.setAttribute("opacity", fmt(1 - open));
      if (sunglasses) {
        sunglasses.setAttribute("transform", `translate(0 ${fmt(glassesOffsetY)}) rotate(${fmt(glassesAngle)} 187 157)`);
      }
      const browState = updateBrows(story);
      if (mouthHappyOpenValue > 1) {
        applyMouthInset(mouthLeft, DEFAULT_MOUTH_LEFT_D, 0);
        applyMouthInset(mouthRight, DEFAULT_MOUTH_RIGHT_D, 0);
        applyHappyMouthPose(mouthHappyOpenValue, mouthHappyPulseValue);
      } else {
        applyHappyMouthPose(0, 0);
        applyMouthInset(mouthLeft, DEFAULT_MOUTH_LEFT_D, mouthInsetValue);
        applyMouthInset(mouthRight, DEFAULT_MOUTH_RIGHT_D, mouthInsetValue);
      }

      headXOut.textContent = fmt(x);
      headYOut.textContent = fmt(y);
      headRotateOut.textContent = fmt(rotate);
      headYawOut.textContent = fmt(yaw);
      eyesOpenOut.textContent = fmt(open);
      glassesYOut.textContent = fmt(glassesOffsetY);
      glassesRotateOut.textContent = fmt(glassesAngle);
      mouthFocusInsetOut.textContent = fmt(Number(mouthFocusInset.value));
      mouthThinkingMinOut.textContent = fmt(Number(mouthThinkingMin.value));
      mouthThinkingMaxOut.textContent = fmt(Number(mouthThinkingMax.value));
      mouthHappyInsetOut.textContent = fmt(Number(mouthHappyInset.value));
      mouthHappyOpenOut.textContent = fmt(Number(mouthHappyOpen.value));
      mouthHappyPulseOut.textContent = fmt(Number(mouthHappyPulse.value));
      browFocusDropOut.textContent = fmt(Number(browFocusDrop.value));
      browThinkTiltOut.textContent = fmt(Number(browThinkTilt.value));
      browHappyLiftOut.textContent = fmt(Number(browHappyLift.value));
      browHappyBounceOut.textContent = fmt(Number(browHappyBounce.value));
      return {
        x,
        y,
        rotate,
        yaw,
        open,
        glassesOffsetY,
        glassesAngle,
        mouthInset: mouthInsetValue,
        mouthHappyOpen: mouthHappyOpenValue,
        mouthHappyPulse: mouthHappyPulseValue,
        brow: browState
      };
    }

    function vecAdd(a, b) {
      return { x: a.x + b.x, y: a.y + b.y };
    }

    function vecSub(a, b) {
      return { x: a.x - b.x, y: a.y - b.y };
    }

    function vecScale(v, amount) {
      return { x: v.x * amount, y: v.y * amount };
    }

    function vecDot(a, b) {
      return a.x * b.x + a.y * b.y;
    }

    function vecNormalize(v) {
      const length = Math.max(0.001, Math.hypot(v.x, v.y));
      return { x: v.x / length, y: v.y / length };
    }

    function pointFromAngle(angle, length) {
      const radians = angle * Math.PI / 180;
      return { x: Math.cos(radians) * length, y: Math.sin(radians) * length };
    }

    function leftHandFkSpec(elbowAngle, elbowOut) {
      const root = { x: LEFT_HAND_ROOT_X, y: LEFT_HAND_CENTER_Y };
      const neutralWrist = { x: LEFT_HAND_WRIST_X, y: LEFT_HAND_WRIST_Y };
      const sourceTip = { x: LEFT_HAND_SOURCE_PAW_TIP_X, y: LEFT_HAND_SOURCE_PAW_TIP_Y };
      const neutralArm = vecSub(neutralWrist, root);
      const armLength = Math.hypot(neutralArm.x, neutralArm.y);
      const upperLength = clamp(armLength * LEFT_HAND_UPPER_RATIO + elbowOut, armLength * 0.25, armLength * 0.84);
      const forearmLength = armLength - upperLength;
      const upperAngle = Math.atan2(neutralArm.y, neutralArm.x) * 180 / Math.PI;
      const forearmAngle = upperAngle + elbowAngle;
      const elbow = vecAdd(root, pointFromAngle(upperAngle, upperLength));
      const wrist = vecAdd(elbow, pointFromAngle(forearmAngle, forearmLength));
      const pawLength = Math.hypot(sourceTip.x - neutralWrist.x, sourceTip.y - neutralWrist.y);
      const tip = vecAdd(wrist, pointFromAngle(forearmAngle, pawLength));
      return { root, elbow, wrist, tip, radius: LEFT_HAND_RADIUS };
    }

    function rigidLeftPawTipPath(spec) {
      const sourceSeam = { x: LEFT_HAND_WRIST_X, y: LEFT_HAND_WRIST_Y };
      const sourceTip = { x: LEFT_HAND_SOURCE_PAW_TIP_X, y: LEFT_HAND_SOURCE_PAW_TIP_Y };
      const sourceVector = vecSub(sourceTip, sourceSeam);
      const targetVector = vecSub(spec.tip, spec.wrist);
      const sourceLength = Math.max(0.001, Math.hypot(sourceVector.x, sourceVector.y));
      const targetLength = Math.max(0.001, Math.hypot(targetVector.x, targetVector.y));
      const sourceAxis = vecNormalize(sourceVector);
      const targetAxis = vecNormalize(targetVector);
      const sourceNormal = { x: -sourceAxis.y, y: sourceAxis.x };
      const targetNormal = { x: -targetAxis.y, y: targetAxis.x };
      const alongScale = targetLength / sourceLength;
      const acrossScale = spec.radius / LEFT_HAND_RADIUS;
      const seamControl = vecAdd(sourceSeam, vecScale(sourceAxis, -7.5 * LEFT_HAND_PAW_SEAM_CURVE));
      const sourceD = `${LEFT_HAND_PAW_SOURCE_D_PREFIX} C${fmt(seamControl.x)} 278.2 ${fmt(seamControl.x)} 257.8 ${fmt(sourceSeam.x)} 249.5 Z`;

      return transformPathPairs(sourceD, (point) => {
        const fromSeam = vecSub(point, sourceSeam);
        const along = vecDot(fromSeam, sourceAxis) * alongScale;
        const across = vecDot(fromSeam, sourceNormal) * acrossScale;
        return vecAdd(spec.wrist, vecAdd(vecScale(targetAxis, along), vecScale(targetNormal, across)));
      });
    }

    function transformLeftHandPoint(point, x, y, scale, thickness, rotate) {
      const radians = rotate * Math.PI / 180;
      const localX = (point.x - LEFT_HAND_ROOT_X) * scale;
      const localY = (point.y - LEFT_HAND_ROOT_Y) * scale * thickness;
      return {
        x: x + localX * Math.cos(radians) - localY * Math.sin(radians),
        y: y + localX * Math.sin(radians) + localY * Math.cos(radians)
      };
    }

    function buildLeftHandPaths(elbowAngle, elbowOut) {
      const spec = leftHandFkSpec(elbowAngle, elbowOut);
      return {
        baseD: `M${fmt(spec.root.x)} ${fmt(spec.root.y)} L${fmt(spec.elbow.x)} ${fmt(spec.elbow.y)} L${fmt(spec.wrist.x)} ${fmt(spec.wrist.y)}`,
        pawD: rigidLeftPawTipPath(spec),
        elbow: spec.elbow,
        wrist: spec.wrist,
        tip: spec.tip
      };
    }

    function updateLeftHand() {
      const x = Number(leftHandX.value);
      const y = Number(leftHandY.value);
      const scale = Number(leftHandScale.value);
      const thickness = Number(leftHandThickness.value);
      const rotate = Number(leftHandRotate.value);
      const elbowAngle = Number(leftHandElbowAngle.value);
      const elbowOut = Number(leftHandElbowOut.value);
      const opacity = clamp(Number(leftHandOpacity.value), 0, 1);
      const handPaths = buildLeftHandPaths(elbowAngle, elbowOut);
      const elbow = transformLeftHandPoint(handPaths.elbow, x, y, scale, thickness, rotate);
      const tip = transformLeftHandPoint(handPaths.tip, x, y, scale, thickness, rotate);

      if (leftHandLayer) {
        leftHandLayer.setAttribute("opacity", fmt(opacity));
        leftHandLayer.setAttribute(
          "transform",
          `translate(${fmt(x)} ${fmt(y)}) rotate(${fmt(rotate)}) scale(${fmt(scale)} ${fmt(scale * thickness)}) translate(${fmt(-LEFT_HAND_ROOT_X)} ${fmt(-LEFT_HAND_ROOT_Y)})`
        );
      }
      if (leftHandBasePath) {
        leftHandBasePath.setAttribute("d", handPaths.baseD);
        leftHandBasePath.setAttribute("fill", "none");
        leftHandBasePath.setAttribute("stroke", "#fff8f0");
        leftHandBasePath.setAttribute("stroke-width", fmt(LEFT_HAND_ARM_WIDTH));
        leftHandBasePath.setAttribute("stroke-linecap", "round");
        leftHandBasePath.setAttribute("stroke-linejoin", "round");
        leftHandBasePath.setAttribute("data-motion", "hard-elbow-angle-arm-stroke");
      }
      if (leftPawTipPath) {
        leftPawTipPath.setAttribute("d", handPaths.pawD);
        leftPawTipPath.setAttribute("fill", "#d8a686");
        leftPawTipPath.removeAttribute("stroke");
        leftPawTipPath.removeAttribute("stroke-width");
        leftPawTipPath.removeAttribute("stroke-linecap");
        leftPawTipPath.removeAttribute("stroke-linejoin");
        leftPawTipPath.setAttribute("data-motion", "rigid-v18-paw-tip-on-wrist");
      }
      if (leftHandCutoutLayer) {
        leftHandCutoutLayer.setAttribute("opacity", "0");
        leftHandCutoutLayer.setAttribute("display", "none");
      }
      if (leftHandIdleBackLayer) {
        leftHandIdleBackLayer.setAttribute("opacity", fmt(clamp(leftHandIdleBackVisible, 0, 1)));
      }
      if (leftHandIdleBackShadowLayer) {
        leftHandIdleBackShadowLayer.setAttribute("opacity", fmt(clamp(leftHandIdleBackVisible, 0, 1)));
      }
      if (leftHandCenterGuide) {
        leftHandCenterGuide.setAttribute("cx", fmt(x));
        leftHandCenterGuide.setAttribute("cy", fmt(y));
      }
      if (leftHandElbowGuide) {
        leftHandElbowGuide.setAttribute("cx", fmt(elbow.x));
        leftHandElbowGuide.setAttribute("cy", fmt(elbow.y));
      }
      if (leftHandPivotGuide) {
        leftHandPivotGuide.setAttribute("cx", fmt(tip.x));
        leftHandPivotGuide.setAttribute("cy", fmt(tip.y));
      }

      leftHandXOut.textContent = fmt(x);
      leftHandYOut.textContent = fmt(y);
      leftHandScaleOut.textContent = fmt(scale);
      leftHandThicknessOut.textContent = fmt(thickness);
      leftHandRotateOut.textContent = fmt(rotate);
      leftHandElbowAngleOut.textContent = fmt(elbowAngle);
      leftHandElbowOutOut.textContent = fmt(elbowOut);
      leftHandPivotXOut.textContent = "0";
      leftHandPivotYOut.textContent = "0";
      leftHandOpacityOut.textContent = fmt(opacity);
      return { x, y, scale, thickness, elbowAngle, elbowOut, elbowX: elbow.x, elbowY: elbow.y, rotate, tipX: tip.x, tipY: tip.y, opacity, idleBack: clamp(leftHandIdleBackVisible, 0, 1) };
    }

    function updateRightHand() {
      const x = Number(rightHandX.value);
      const y = Number(rightHandY.value);
      const scale = Number(rightHandScale.value);
      const rotate = Number(rightHandRotate.value);
      const opacity = clamp(Number(rightHandOpacity.value), 0, 1);
      const w = RIGHT_HAND_BASE_WIDTH;
      const h = RIGHT_HAND_BASE_HEIGHT;

      if (rightHandNoRodImage) {
        rightHandNoRodImage.setAttribute("x", fmt(-w / 2));
        rightHandNoRodImage.setAttribute("y", fmt(-h / 2));
        rightHandNoRodImage.setAttribute("width", fmt(w));
        rightHandNoRodImage.setAttribute("height", fmt(h));
      }
      if (rightHandNoRodLayer) {
        rightHandNoRodLayer.setAttribute("opacity", fmt(opacity));
        rightHandNoRodLayer.setAttribute("transform", `translate(${fmt(x)} ${fmt(y)})`);
      }
      if (rightHandIdleBackLayer) {
        rightHandIdleBackLayer.setAttribute("opacity", fmt(clamp(rightHandIdleBackVisible, 0, 1)));
      }
      if (rightHandIdleBackShadowLayer) {
        rightHandIdleBackShadowLayer.setAttribute("opacity", fmt(clamp(rightHandIdleBackVisible, 0, 1)));
      }
      if (rightHandNoRodLocal) {
        rightHandNoRodLocal.setAttribute("transform", `rotate(${fmt(rotate)}) scale(${fmt(scale)})`);
      }
      if (rightHandPivotGuide) {
        rightHandPivotGuide.setAttribute("cx", fmt(x));
        rightHandPivotGuide.setAttribute("cy", fmt(y));
      }

      rightHandXOut.textContent = fmt(x);
      rightHandYOut.textContent = fmt(y);
      rightHandScaleOut.textContent = fmt(scale);
      rightHandRotateOut.textContent = fmt(rotate);
      rightHandOpacityOut.textContent = fmt(opacity);
      return { x, y, scale, rotate, opacity, idleBack: clamp(rightHandIdleBackVisible, 0, 1), width: w, height: h };
    }

    function updateBackCards() {
      const x = Number(backCardsX.value);
      const y = Number(backCardsY.value);
      const scale = Number(backCardsScale.value);
      const rotate = Number(backCardsRotate.value);
      const opacity = clamp(Number(backCardsOpacity.value), 0, 1);
      const w = BACK_CARDS_BASE_WIDTH;
      const h = BACK_CARDS_BASE_HEIGHT;

      if (backCardsImage) {
        backCardsImage.setAttribute("x", fmt(-w / 2));
        backCardsImage.setAttribute("y", fmt(-h / 2));
        backCardsImage.setAttribute("width", fmt(w));
        backCardsImage.setAttribute("height", fmt(h));
      }
      if (backCardsLayer) {
        backCardsLayer.setAttribute("opacity", fmt(opacity));
        backCardsLayer.setAttribute("transform", `translate(${fmt(x)} ${fmt(y)})`);
      }
      if (backCardsLocal) {
        backCardsLocal.setAttribute("transform", `rotate(${fmt(rotate)}) scale(${fmt(scale)})`);
      }
      if (backCardsCenterGuide) {
        backCardsCenterGuide.setAttribute("cx", fmt(x));
        backCardsCenterGuide.setAttribute("cy", fmt(y));
      }

      backCardsXOut.textContent = fmt(x);
      backCardsYOut.textContent = fmt(y);
      backCardsScaleOut.textContent = fmt(scale);
      backCardsRotateOut.textContent = fmt(rotate);
      backCardsOpacityOut.textContent = fmt(opacity);
      return { x, y, scale, rotate, opacity, width: w, height: h };
    }

    function updateFishingGear() {
      const x = Number(fishingGearX.value);
      const y = Number(fishingGearY.value);
      const scale = Number(fishingGearScale.value);
      const rotate = Number(fishingGearRotate.value);
      const opacity = clamp(Number(fishingGearOpacity.value), 0, 1);
      const w = FISHING_GEAR_BASE_WIDTH;
      const h = FISHING_GEAR_BASE_HEIGHT;

      if (fishingGearImage) {
        fishingGearImage.setAttribute("x", fmt(-w / 2));
        fishingGearImage.setAttribute("y", fmt(-h / 2));
        fishingGearImage.setAttribute("width", fmt(w));
        fishingGearImage.setAttribute("height", fmt(h));
      }
      if (fishingGearLayer) {
        fishingGearLayer.setAttribute("opacity", fmt(opacity));
        fishingGearLayer.setAttribute("transform", `translate(${fmt(x)} ${fmt(y)})`);
      }
      if (fishingGearLocal) {
        fishingGearLocal.setAttribute("transform", `rotate(${fmt(rotate)}) scale(${fmt(scale)})`);
      }
      if (fishingGearCenterGuide) {
        fishingGearCenterGuide.setAttribute("cx", fmt(x));
        fishingGearCenterGuide.setAttribute("cy", fmt(y));
      }

      fishingGearXOut.textContent = fmt(x);
      fishingGearYOut.textContent = fmt(y);
      fishingGearScaleOut.textContent = fmt(scale);
