      return { x, y, scale, rotate, opacity, width: w, height: h };
    }

    function updateFishTerminal() {
      const x = Number(fishTerminalX.value);
      const y = Number(fishTerminalY.value);
      const scale = Number(fishTerminalScale.value);
      const rotate = Number(fishTerminalRotate.value);
      const opacity = clamp(Number(fishTerminalOpacity.value), 0, 1);
      const motion = fishTerminalMotionState();
      const storyScale = fishTerminalStoryScale || 1;
      const storyDy = fishTerminalStoryDy || 0;
      const storyRotate = fishTerminalStoryRotate || 0;

      if (fishTerminalLayer) {
        fishTerminalLayer.setAttribute("opacity", fmt(opacity));
        fishTerminalLayer.setAttribute("transform", `translate(${fmt(x + motion.terminalDx)} ${fmt(y + motion.terminalDy + storyDy)})`);
      }
      if (fishTerminalLocal) {
        fishTerminalLocal.setAttribute(
          "transform",
          `rotate(${fmt(rotate + motion.terminalRotate + storyRotate)}) scale(${fmtScale(scale * motion.terminalScaleX * storyScale)} ${fmtScale(scale * motion.terminalScaleY * storyScale)})`
        );
      }
      if (fishTerminalCenterGuide) {
        fishTerminalCenterGuide.setAttribute("cx", fmt(x));
        fishTerminalCenterGuide.setAttribute("cy", fmt(y));
      }
      applyFishTerminalInternalMotion(motion);

      fishTerminalXOut.textContent = fmt(x);
      fishTerminalYOut.textContent = fmt(y);
      fishTerminalScaleOut.textContent = fmt(scale);
      fishTerminalRotateOut.textContent = fmt(rotate);
      fishTerminalOpacityOut.textContent = fmt(opacity);
      fishTerminalPhaseOut.textContent = fmt(motion.phase);
      fishTerminalSpeedOut.textContent = fmt(motion.speed);
      fishTerminalFloatOut.textContent = fmt(motion.floatAmount);
      fishTerminalBreathOut.textContent = fmt(motion.breathAmount);
      fishTerminalSwayOut.textContent = fmt(motion.swayAmount);
      fishSwimOut.textContent = fmt(motion.swim);
      fishMinXOut.textContent = fmt(motion.fishMinX);
      fishMaxXOut.textContent = fmt(motion.fishMaxX);
      fishBaseYOut.textContent = fmt(motion.fishBaseY);
      fishYRangeOut.textContent = fmt(motion.fishYRange);
      waterSpreadOut.textContent = fmt(motion.waterSpread);
      return { x, y, scale, rotate, opacity, ...motion };
    }

    function fishTerminalMotionState() {
      const phase = ((Number(fishTerminalPhase.value) % 1) + 1) % 1;
      const speed = Number(fishTerminalSpeed.value);
      const floatAmount = Number(fishTerminalFloat.value);
      const breathAmount = Number(fishTerminalBreath.value);
      const swayAmount = Number(fishTerminalSway.value);
      const swim = Number(fishSwim.value);
      const bite = biteMotionState();
      const fishLeft = Math.min(Number(fishMinX.value), Number(fishMaxX.value));
      const fishRight = Math.max(Number(fishMinX.value), Number(fishMaxX.value));
      const fishBase = Number(fishBaseY.value);
      const fishVerticalRange = Number(fishYRange.value);
      const waterSpreadAmount = Number(waterSpread.value);
      const tau = Math.PI * 2;
      const storyExit = clamp(fishTerminalStoryExit || 0, 0, 1);
      const storyExitRaw = clamp(fishTerminalStoryExitRaw || 0, 0, 1);
      const exitKick = Math.sin(Math.PI * storyExitRaw);
      const exitPhase = (phase + storyExitRaw * 0.42) % 1;
      const bob = Math.sin(tau * exitPhase);
      const softBob = Math.sin(tau * exitPhase + 0.58);
      const breath = Math.sin(tau * exitPhase - 0.18);
      const swimWave = Math.sin(tau * bite.swimLoopPhase - Math.PI / 2);
      const swimVelocity = Math.cos(tau * bite.swimLoopPhase - Math.PI / 2);
      const fishMid = (fishLeft + fishRight) / 2;
      const fishHalfRange = (fishRight - fishLeft) / 2;
      const biteApproach = clamp(bite.approach * bite.fishLunge, 0, 1);
      const biteJab = bite.pulse * bite.fishLunge;
      const freeFishX = fishMid + swimWave * fishHalfRange;
      const freeFishY = fishBase + Math.sin(tau * bite.swimLoopPhase * 2 + 0.35) * fishVerticalRange * swim;
      const biteTargetX = 218;
      const biteTargetY = 174;
      const biteFishX = lerp(freeFishX, biteTargetX, biteApproach) - biteJab * 14;
      const biteFishY = lerp(freeFishY, biteTargetY, biteApproach) - biteJab * 9;
      const escapeX = fishLeft;
      const escapeY = fishBase + 8;
      const fishX = lerp(biteFishX, escapeX, bite.escape);
      const fishY = lerp(biteFishY, escapeY, bite.escape);
      const freeFishAngle = swimVelocity * 4.5 * swim;
      const biteAngle = lerp(freeFishAngle, 16, biteApproach) + bite.firstPulse * 5 + bite.secondPulse * 9;
      const fishAngle = lerp(biteAngle, -4, bite.escape);
      const fishDir = biteApproach > 0.05 || bite.escape > 0.05 ? 1 : (swimVelocity >= 0 ? -1 : 1);
      const exitFishX = lerp(fishX, fishRight - 34, storyExit) + Math.sin(tau * storyExitRaw * 1.35) * 18 * exitKick;
      const exitFishY = lerp(fishY, fishBase + 24, storyExit) + Math.sin(tau * storyExitRaw * 2 + 0.4) * 12 * exitKick;
      const exitFishAngle = lerp(fishAngle, 9, storyExit) + Math.sin(tau * storyExitRaw * 2.2) * 9 * exitKick;
      const exitFishDir = storyExitRaw > 0.03 ? -1 : fishDir;
      const exitRipple = exitKick * 0.42;
      const exitRippleX = 244 + Math.sin(tau * storyExitRaw * 1.1) * 5 * exitKick;
      const exitRippleY = 216 + Math.sin(tau * exitPhase + 1.1) * 4 * exitKick;
      return {
        phase: exitPhase,
        speed,
        floatAmount,
        breathAmount,
        swayAmount,
        swim,
        fishMinX: fishLeft,
        fishMaxX: fishRight,
        fishBaseY: fishBase,
        fishYRange: fishVerticalRange,
        waterSpread: waterSpreadAmount + exitKick * 0.45,
        terminalDx: Math.sin(tau * exitPhase + 1.7) * floatAmount * 0.16,
        terminalDy: bob * floatAmount,
        terminalRotate: softBob * swayAmount,
        terminalScaleX: 1 + breath * breathAmount * 0.02,
        terminalScaleY: 1 - breath * breathAmount * 0.015,
        fishX: exitFishX,
        fishY: exitFishY,
        fishAngle: exitFishAngle,
        fishDir: exitFishDir,
        bite: Math.min(1.35, Math.max(bite.pulse, exitRipple)),
        bitePhase: bite.phase,
        biteApproach,
        biteEscape: bite.escape,
        biteStage: bite.stage,
        biteRippleX: storyExitRaw > 0.03 ? exitRippleX : 244,
        biteRippleY: storyExitRaw > 0.03 ? exitRippleY : 216,
        storyExit,
        storyExitRaw
      };
    }

    function spreadWaterX(x, amount) {
      const center = 245;
      return center + (x - center) * (1 + amount);
    }

    function buildWaterMainPath(motion) {
      const tau = Math.PI * 2;
      const spread = motion.waterSpread;
      const horizontal = Math.sin(tau * motion.phase) * 0.045 * spread;
      const lift = Math.sin(tau * motion.phase * 2 + 0.4) * 4 * spread;
      const x = (value) => fmt(spreadWaterX(value, horizontal));
      const y = (base, scale = 1) => fmt(base + lift * scale);
      return [
        `M30 ${y(157)}`,
        `C${x(77)} ${y(140, -0.85)} ${x(117)} ${y(174, 0.65)} ${x(163)} ${y(160, 0.2)}`,
        `C${x(212)} ${y(146, -0.55)} ${x(248)} ${y(178, 0.7)} ${x(299)} ${y(160, 0.15)}`,
        `C${x(349)} ${y(143, -0.65)} ${x(397)} ${y(175, 0.55)} 460 ${y(160, 0.2)}`,
        "L460 352 L30 352 Z"
      ].join(" ");
    }

    function buildWaterRidgePath(motion) {
      const tau = Math.PI * 2;
      const spread = motion.waterSpread;
      const horizontal = Math.sin(tau * motion.phase) * 0.045 * spread;
      const lift = Math.sin(tau * motion.phase * 2 + 0.4) * 3.2 * spread;
      const x = (value) => fmt(spreadWaterX(value, horizontal));
      const y = (base, scale = 1) => fmt(base + lift * scale);
      return [
        `M30 ${y(159, 0.75)}`,
        `C${x(78)} ${y(149, -0.65)} ${x(118)} ${y(182, 0.8)} ${x(165)} ${y(169, 0.35)}`,
        `C${x(215)} ${y(156, -0.55)} ${x(250)} ${y(187, 0.7)} ${x(302)} ${y(171, 0.25)}`,
        `C${x(351)} ${y(156, -0.55)} ${x(399)} ${y(186, 0.65)} 460 ${y(171, 0.3)}`,
        `L460 ${y(199, 0.35)}`,
        `C${x(401)} ${y(208, 0.65)} ${x(354)} ${y(184, -0.45)} ${x(303)} ${y(198, 0.35)}`,
        `C${x(251)} ${y(212, 0.75)} ${x(214)} ${y(182, -0.55)} ${x(165)} ${y(196, 0.3)}`,
        `C${x(117)} ${y(209, 0.7)} ${x(76)} ${y(179, -0.45)} 30 ${y(190, 0.25)} Z`
      ].join(" ");
    }

    function applyFishTerminalInternalMotion(motion) {
      if (fishTerminalWaterMain) {
        fishTerminalWaterMain.setAttribute("d", buildWaterMainPath(motion));
        fishTerminalWaterMain.removeAttribute("transform");
      }
      if (fishTerminalWaterRidge) {
        fishTerminalWaterRidge.setAttribute("d", buildWaterRidgePath(motion));
        fishTerminalWaterRidge.removeAttribute("transform");
        fishTerminalWaterRidge.setAttribute("opacity", fmt(0.58 + 0.2 * Math.sin(Math.PI * 2 * motion.phase + 0.9)));
      }
      if (fishTerminalFish) {
        const cx = 65;
        const cy = 58;
        fishTerminalFish.setAttribute(
          "transform",
          `translate(${fmt(motion.fishX)} ${fmt(motion.fishY)}) translate(${cx} ${cy}) scale(${motion.fishDir} 1) rotate(${fmt(motion.fishAngle * motion.fishDir)}) translate(${-cx} ${-cy})`
        );
      }
      fishTerminalBubbles.forEach((bubble, index) => {
        if (!bubble) return;
        const offsets = [0.08, 0.34, 0.58, 0.82];
        const t = (motion.phase + offsets[index]) % 1;
        const rise = -34 * t;
        const sway = Math.sin(Math.PI * 2 * (motion.phase + offsets[index] * 0.7)) * (index % 2 ? 5.5 : 3.5);
        const opacity = 0.18 + (1 - t) * 0.72;
        bubble.setAttribute("transform", `translate(${fmt(sway)} ${fmt(rise)})`);
        bubble.setAttribute("opacity", fmt(opacity));
      });
      const rippleX = motion.bite > 0.02 ? motion.biteRippleX : clamp(motion.fishX + 65, 70, 390);
      const rippleY = motion.bite > 0.02 ? motion.biteRippleY : clamp(motion.fishY + 52 + Math.sin(Math.PI * 2 * motion.phase + 1.1) * 4, 126, 330);
      const rippleScale = 0.65 + motion.bite * 1.25;
      if (fishTerminalRippleA) {
        fishTerminalRippleA.setAttribute("cx", fmt(rippleX));
        fishTerminalRippleA.setAttribute("cy", fmt(rippleY));
        fishTerminalRippleA.setAttribute("rx", fmt(34 * rippleScale));
        fishTerminalRippleA.setAttribute("ry", fmt(12 * rippleScale));
        fishTerminalRippleA.setAttribute("opacity", fmt(motion.bite * 0.56));
      }
      if (fishTerminalRippleB) {
        fishTerminalRippleB.setAttribute("cx", fmt(rippleX));
        fishTerminalRippleB.setAttribute("cy", fmt(rippleY));
        fishTerminalRippleB.setAttribute("rx", fmt(20 * (0.75 + motion.bite * 0.85)));
        fishTerminalRippleB.setAttribute("ry", fmt(7 * (0.75 + motion.bite * 0.85)));
        fishTerminalRippleB.setAttribute("opacity", fmt(motion.bite * 0.42));
      }
    }

    function setStoryMotionPlaying(playing) {
      storyMotionPlaying = playing;
      storyMotionPlay.textContent = playing ? "Pause" : "Play";
      if (playing) {
        activeStoryKeyframeName = "播放中";
        updateKeyframeSelection();
        setBiteMotionPlaying(false);
        storyMotionLastTs = performance.now();
        if (!storyMotionTimer) storyMotionTimer = setInterval(tickStoryMotion, 1000 / 60);
      } else if (storyMotionTimer) {
        clearInterval(storyMotionTimer);
        storyMotionTimer = 0;
      }
    }

    function tickStoryMotion() {
      if (!storyMotionPlaying) {
        if (storyMotionTimer) {
          clearInterval(storyMotionTimer);
          storyMotionTimer = 0;
        }
        return;
      }
      const now = performance.now();
      const dt = clamp((now - storyMotionLastTs) / 1000, 0, 0.08);
      storyMotionLastTs = now;
      const speed = Number(storyMotionSpeed.value);
      const rawNextPhase = Number(storyMotionPhase.value) + dt * speed / STORY_MOTION_LOOP_SECONDS;
      let nextPhase = rawNextPhase;
      if (nextPhase >= 1) {
        nextPhase = EXPORT_STORY_PHASE_START + ((nextPhase - 1) % EXPORT_STORY_PHASE_WRAP_SPAN);
      }
      storyMotionPhase.value = nextPhase.toFixed(4);
      applyStoryMotionToInputs();
      updateAll();
    }

    function setFishTerminalPlaying(playing) {
      fishTerminalPlaying = playing;
      fishTerminalPlay.textContent = playing ? "Pause" : "Play";
      if (playing) {
        fishTerminalLastTs = performance.now();
        if (!fishTerminalTimer) fishTerminalTimer = setInterval(tickFishTerminalMotion, 1000 / 30);
      } else if (fishTerminalTimer) {
        clearInterval(fishTerminalTimer);
        fishTerminalTimer = 0;
      }
    }

    function tickFishTerminalMotion() {
      if (!fishTerminalPlaying) {
        if (fishTerminalTimer) {
          clearInterval(fishTerminalTimer);
          fishTerminalTimer = 0;
        }
        return;
      }
      const now = performance.now();
      const dt = clamp((now - fishTerminalLastTs) / 1000, 0, 0.08);
      fishTerminalLastTs = now;
      const speed = Number(fishTerminalSpeed.value);
      const nextPhase = (Number(fishTerminalPhase.value) + dt * speed / FISH_TERMINAL_LOOP_SECONDS) % 1;
      fishTerminalPhase.value = nextPhase.toFixed(3);
      updateFishTerminal();
    }

    function applyCodeTerminalContentMotion(story) {
      const contentOpacity = clamp(story.code.contentOpacity, 0, 1);
      const contentTransform = `translate(0 ${fmt(story.code.contentDy)})`;
      if (codeTerminalCodeIcons) {
        codeTerminalCodeIcons.setAttribute("opacity", fmt(contentOpacity));
        codeTerminalCodeIcons.setAttribute("transform", contentTransform);
      }
      if (codeTerminalCodeLines) {
        codeTerminalCodeLines.setAttribute("opacity", fmt(contentOpacity));
        codeTerminalCodeLines.setAttribute("transform", contentTransform);
      }
      codeTerminalCodeLineNodes.forEach((line, index) => {
        const reveal = smooth01(clamp((story.code.contentReveal - index * 0.085) / 0.34, 0, 1));
        const x1 = Number(line.getAttribute("x1"));
        const x2 = Number(line.getAttribute("x2"));
        const length = Math.max(1, Math.abs(x2 - x1));
        line.setAttribute("stroke-dasharray", fmt(length));
        line.setAttribute("stroke-dashoffset", fmt(length * (1 - reveal)));
      });
    }

    function updateCodeTerminal() {
      const x = Number(codeTerminalX.value);
      const y = Number(codeTerminalY.value);
      const scale = Number(codeTerminalScale.value);
      const rotate = Number(codeTerminalRotate.value);
      const opacity = clamp(Number(codeTerminalOpacity.value), 0, 1);
      const story = storyMotionState();
      const storyScale = story.code.scale;
      const effectiveOpacity = opacity * story.code.opacity;
      const effectiveScale = scale * storyScale;

      if (codeTerminalLayer) {
        codeTerminalLayer.setAttribute("opacity", fmt(effectiveOpacity));
        codeTerminalLayer.setAttribute("transform", `translate(${fmt(x)} ${fmt(y + story.code.dy)})`);
      }
      if (codeTerminalLocal) {
        codeTerminalLocal.setAttribute("transform", `rotate(${fmt(rotate)}) scale(${fmtScale(effectiveScale)})`);
      }
      if (codeTerminalCenterGuide) {
        codeTerminalCenterGuide.setAttribute("cx", fmt(x));
        codeTerminalCenterGuide.setAttribute("cy", fmt(y));
      }
      applyCodeTerminalContentMotion(story);

      codeTerminalXOut.textContent = fmt(x);
      codeTerminalYOut.textContent = fmt(y);
      codeTerminalScaleOut.textContent = fmt(scale);
      codeTerminalRotateOut.textContent = fmt(rotate);
      codeTerminalOpacityOut.textContent = fmt(effectiveOpacity);
      return { x, y, scale, rotate, opacity, effectiveOpacity, effectiveScale };
    }

    function updateChatTerminal() {
      const x = Number(chatTerminalX.value);
      const y = Number(chatTerminalY.value);
      const scale = Number(chatTerminalScale.value);
      const rotate = Number(chatTerminalRotate.value);
      const opacity = clamp(Number(chatTerminalOpacity.value), 0, 1);
      const story = storyMotionState();
      const storyScale = story.chat.scale;
      const effectiveOpacity = opacity * story.chat.opacity;
      const effectiveScale = scale * storyScale;

      if (chatTerminalLayer) {
        chatTerminalLayer.setAttribute("opacity", fmt(effectiveOpacity));
        chatTerminalLayer.setAttribute("transform", `translate(${fmt(x)} ${fmt(y + story.chat.dy)})`);
      }
      if (chatTerminalLocal) {
        chatTerminalLocal.setAttribute("transform", `rotate(${fmt(rotate)}) scale(${fmtScale(effectiveScale)})`);
      }
      chatMessageLayers.forEach((layer, index) => {
        const reveal = clamp(story.chat.messages?.[index] ?? 1, 0, 1);
        const lift = (1 - reveal) * (index === chatMessageLayers.length - 1 ? 12 : 18);
        const overshoot = -Math.sin(Math.PI * reveal) * 3.5;
        layer.setAttribute("opacity", fmt(reveal));
        layer.setAttribute("transform", `translate(0 ${fmt(lift + overshoot)})`);
      });
      if (chatTerminalCenterGuide) {
        chatTerminalCenterGuide.setAttribute("cx", fmt(x));
        chatTerminalCenterGuide.setAttribute("cy", fmt(y));
      }

      chatTerminalXOut.textContent = fmt(x);
      chatTerminalYOut.textContent = fmt(y);
      chatTerminalScaleOut.textContent = fmt(scale);
      chatTerminalRotateOut.textContent = fmt(rotate);
      chatTerminalOpacityOut.textContent = fmt(effectiveOpacity);
      return { x, y, scale, rotate, opacity, effectiveOpacity, effectiveScale };
    }

    function updateThinkingSticker(story) {
      const controlX = Number(thinkingHandX.value);
      const controlY = Number(thinkingHandY.value);
      const controlScale = Number(thinkingHandScale.value);
      const controlRotate = Number(thinkingHandRotate.value);
      const controlOpacity = Number(thinkingHandOpacity.value);
      const currentHeadX = Number(headX.value);
      const currentHeadY = Number(headY.value);
      const currentHeadRotate = Number(headRotate.value);
      const opacity = clamp(story.thinking * controlOpacity, 0, 1);
      const wobble = Math.sin(story.time * Math.PI * 1.35) * opacity;
      const lift = (1 - Math.cos(story.time * Math.PI * 1.35)) * 0.5 * opacity;
      const baseX = controlX + currentHeadX * 0.34;
      const baseY = controlY + currentHeadY * 0.42;
      const baseRotate = controlRotate + currentHeadRotate * 0.18;
      if (thinkingStickerArmLayer) {
        thinkingStickerArmLayer.setAttribute("opacity", fmt(opacity));
        thinkingStickerArmLayer.setAttribute(
          "transform",
          `translate(${fmt(baseX)} ${fmt(baseY - lift * 0.35)}) rotate(${fmt(baseRotate)}) scale(${fmt(controlScale)})`
        );
      }
      if (thinkingStickerPawLayer) {
        thinkingStickerPawLayer.setAttribute("opacity", fmt(opacity));
        thinkingStickerPawLayer.setAttribute(
          "transform",
          `translate(${fmt(baseX + wobble * 0.65)} ${fmt(baseY - lift * 0.85)}) rotate(${fmt(baseRotate + wobble * 2.4)} -12.78 0.42) scale(${fmt(controlScale)})`
        );
      }
      thinkingHandXOut.textContent = fmt(controlX);
      thinkingHandYOut.textContent = fmt(controlY);
      thinkingHandScaleOut.textContent = fmt(controlScale);
      thinkingHandRotateOut.textContent = fmt(controlRotate);
      thinkingHandOpacityOut.textContent = fmt(controlOpacity);
      return { opacity, wobble, lift, baseX, baseY, scale: controlScale, rotate: controlRotate, controlOpacity };
    }

    function pointOnCubic(p0, p1, p2, p3, t) {
      const u = 1 - t;
      return {
        x: u * u * u * p0.x + 3 * u * u * t * p1.x + 3 * u * t * t * p2.x + t * t * t * p3.x,
        y: u * u * u * p0.y + 3 * u * u * t * p1.y + 3 * u * t * t * p2.y + t * t * t * p3.y
      };
    }

    function addPoint(point, dx, dy) {
      return { x: point.x + dx, y: point.y + dy };
    }

    function buildRodCurve(lineX, lineTopY, bend, focus) {
      const start = { x: 190, y: 610 };
      const tip = { x: lineX - 10, y: lineTopY - 3 };
      const dx = tip.x - start.x;
      const dy = tip.y - start.y;
      const focusT = clamp(focus / 1.4, 0, 1);
      const bendPx = bend * 64;
      const c1 = {
        x: start.x + dx * 0.255 - bendPx * 0.04,
        y: start.y + dy * 0.409 + bendPx * lerp(0.34, 0.16, focusT)
      };
      const c2 = {
        x: start.x + dx * 0.573 + bendPx * lerp(0.02, 0.1, focusT),
        y: start.y + dy * 0.763 + bendPx * lerp(0.64, 1.05, focusT)
      };
      const guideA = addPoint(pointOnCubic(start, c1, c2, tip, 0.2), 14, 79);
      const guideB = addPoint(pointOnCubic(start, c1, c2, tip, 0.44), 23, 145);
      const guideC = addPoint(pointOnCubic(start, c1, c2, tip, 0.72), 15, 87);
      return { start, c1, c2, tip, guideA, guideB, guideC, guideTip: { x: lineX, y: lineTopY } };
    }

    function cubicPath(start, c1, c2, tip) {
      return `M${fmt(start.x)} ${fmt(start.y)} C${fmt(c1.x)} ${fmt(c1.y)} ${fmt(c2.x)} ${fmt(c2.y)} ${fmt(tip.x)} ${fmt(tip.y)}`;
    }

    function rodHighlightPath(curve) {
      return cubicPath(
        addPoint(curve.start, -2, 5),
        addPoint(curve.c1, -1, 6),
        addPoint(curve.c2, -2, 8),
        addPoint(curve.tip, -8, 7)
      );
    }

    function biteMotionState() {
      const phase = ((Number(biteMotionPhase.value) % 1) + 1) % 1;
      const speed = Number(biteMotionSpeed.value);
      const strength = Number(biteStrength.value);
      const fishLunge = Number(biteFishLunge.value);
      const bobberDip = Number(biteBobberDip.value);
      const rodKick = Number(biteRodKick.value);
      const swimLoopPhase = phase < BITE_SWIM_END_PHASE ? (phase / BITE_SWIM_END_PHASE * 2) % 1 : 0.98;
      const firstPulse = circularPulse(phase, BITE_FIRST_PULSE_PHASE, 0.018);
      const secondPulse = circularPulse(phase, BITE_SECOND_PULSE_PHASE, 0.02);
      const pulse = clamp((firstPulse + secondPulse * 1.12) * strength, 0, 1.35);
      const approachIn = smooth01(clamp((phase - BITE_SWIM_END_PHASE) / (BITE_APPROACH_END_PHASE - BITE_SWIM_END_PHASE), 0, 1));
      const approachOut = 1 - smooth01(clamp((phase - BITE_BITE_END_PHASE) / 0.04, 0, 1));
      const approach = approachIn * approachOut;
      const escape = smooth01(clamp((phase - BITE_ESCAPE_START_PHASE) / 0.04, 0, 1));
      const stage = phase < BITE_SWIM_END_PHASE
        ? "two-swim-loops"
        : phase < BITE_APPROACH_END_PHASE
          ? "return-to-bobber"
          : phase < BITE_BITE_END_PHASE
            ? "double-bite"
            : "dart-away";
      return {
        phase,
        speed,
        strength,
        fishLunge,
        bobberDip,
        rodKick,
        firstPulse,
        secondPulse,
        pulse,
        approach,
        escape,
        swimLoopPhase,
        stage,
        bobberDy: pulse * bobberDip,
        rodPull: clamp(pulse * rodKick, 0, 1)
      };
    }

    function setBiteMotionPlaying(playing) {
      biteMotionPlaying = playing;
      biteMotionPlay.textContent = playing ? "Pause" : "Play";
      if (playing) {
        biteMotionLastTs = performance.now();
        if (!biteMotionTimer) biteMotionTimer = setInterval(tickBiteMotion, 1000 / 30);
      } else if (biteMotionTimer) {
        clearInterval(biteMotionTimer);
        biteMotionTimer = 0;
      }
    }

    function tickBiteMotion() {
      if (!biteMotionPlaying) {
        if (biteMotionTimer) {
          clearInterval(biteMotionTimer);
          biteMotionTimer = 0;
        }
        return;
      }
      const now = performance.now();
      const dt = clamp((now - biteMotionLastTs) / 1000, 0, 0.08);
      biteMotionLastTs = now;
      const speed = Number(biteMotionSpeed.value);
      const nextPhase = (Number(biteMotionPhase.value) + dt * speed / BITE_MOTION_LOOP_SECONDS) % 1;
      biteMotionPhase.value = nextPhase.toFixed(3);
      updateAll();
    }

    function rodMotionState() {
      const phase = ((Number(rodMotionPhase.value) % 1) + 1) % 1;
      const speed = Number(rodMotionSpeed.value);
      const swing = Number(rodBendSwing.value);
      const tipTravel = Number(rodTipTravel.value);
      const bobberTravel = Number(rodBobberTravel.value);
      const bite = biteMotionState();
      const wave = Math.sin(Math.PI * 2 * phase);
      const curveBend = clamp(Number(rodBend.value) + wave * swing, -1, 1);
      const effectiveBend = lerp(curveBend, 1, bite.rodPull);
      return {
        phase,
        speed,
        swing,
        tipTravel,
        bobberTravel,
        bite,
        wave,
        curveBend,
        effectiveBend,
        tipDy: wave * tipTravel + bite.bobberDy * 0.42,
        bobberDy: effectiveBend * bobberTravel + bite.bobberDy,
        focusBoost: Math.max(0, wave) * 0.22 + bite.rodPull * 0.28
      };
    }

    function setRodMotionPlaying(playing) {
      rodMotionPlaying = playing;
      rodMotionPlay.textContent = playing ? "Pause" : "Play";
      if (playing) {
        rodMotionLastTs = performance.now();
        if (!rodMotionTimer) rodMotionTimer = setInterval(tickRodMotion, 1000 / 30);
      } else if (rodMotionTimer) {
        clearInterval(rodMotionTimer);
        rodMotionTimer = 0;
      }
    }

    function tickRodMotion() {
      if (!rodMotionPlaying) {
        if (rodMotionTimer) {
          clearInterval(rodMotionTimer);
          rodMotionTimer = 0;
        }
        return;
      }
      const now = performance.now();
      const dt = clamp((now - rodMotionLastTs) / 1000, 0, 0.08);
      rodMotionLastTs = now;
      const speed = Number(rodMotionSpeed.value);
      const nextPhase = (Number(rodMotionPhase.value) + dt * speed / ROD_MOTION_LOOP_SECONDS) % 1;
      rodMotionPhase.value = nextPhase.toFixed(3);
      updateAll();
    }

    function updateRodDetails() {
      const handleX = Number(rodHandleX.value);
      const handleY = Number(rodHandleY.value);
      const handleRotateValue = Number(rodHandleRotate.value);
      const lineX = Number(rodLineX.value);
      const lineTopY = Number(rodLineTopY.value);
      const lineBottomY = Number(rodLineBottomY.value);
      const bend = Number(rodBend.value);
      const bendFocus = Number(rodBendFocus.value);
      const motion = rodMotionState();
      const effectiveLineTopY = lineTopY + motion.tipDy;
      const effectiveBendFocus = clamp(bendFocus + motion.focusBoost, 0, 1.4);
      const bobberX = Number(rodBobberX.value);
      const bobberY = Number(rodBobberY.value);
      const bobberRx = Number(rodBobberRx.value);
      const bobberRy = Number(rodBobberRy.value);
      const effectiveLineBottomY = lineBottomY + motion.bobberDy;
      const effectiveBobberY = bobberY + motion.bobberDy;
      const curve = buildRodCurve(lineX, effectiveLineTopY, motion.effectiveBend, effectiveBendFocus);

      if (rodHandleGroup) {
        rodHandleGroup.setAttribute("transform", `translate(${fmt(handleX)} ${fmt(handleY)}) rotate(${fmt(handleRotateValue)} 155 650)`);
      }
      if (rodMain) {
        rodMain.setAttribute("d", cubicPath(curve.start, curve.c1, curve.c2, curve.tip));
      }
      if (rodHighlight) {
        rodHighlight.setAttribute("d", rodHighlightPath(curve));
      }
      if (rodSupportLineA) {
        const supportAStart = addPoint(curve.guideA, -48, -30);
        const supportAEnd = addPoint(curve.guideB, -23, 29);
        const supportAC1 = addPoint(curve.guideA, 18, 32);
        const supportAC2 = addPoint(curve.guideB, -73, 94);
        rodSupportLineA.setAttribute("d", cubicPath(supportAStart, supportAC1, supportAC2, supportAEnd));
      }
      if (rodSupportLineB) {
        const supportBStart = addPoint(curve.guideB, -23, 29);
        const supportBEnd = curve.tip;
        const sdx = supportBEnd.x - supportBStart.x;
        const sdy = supportBEnd.y - supportBStart.y;
        const bendPx = motion.effectiveBend * 28;
        const supportBC1 = {
          x: supportBStart.x + sdx * 0.29,
          y: supportBStart.y + sdy * 0.32 + bendPx * 0.2
        };
        const supportBC2 = {
          x: supportBStart.x + sdx * 0.6,
          y: supportBStart.y + sdy * 0.66 + bendPx * 0.35
        };
        rodSupportLineB.setAttribute("d", cubicPath(supportBStart, supportBC1, supportBC2, supportBEnd));
      }
      if (rodFishingLine) {
        rodFishingLine.setAttribute("d", `M${fmt(curve.guideTip.x)} ${fmt(curve.guideTip.y)} L${fmt(bobberX)} ${fmt(effectiveLineBottomY)}`);
      }
      if (rodGuideA) {
        rodGuideA.setAttribute("cx", fmt(curve.guideA.x));
        rodGuideA.setAttribute("cy", fmt(curve.guideA.y));
      }
      if (rodGuideB) {
        rodGuideB.setAttribute("cx", fmt(curve.guideB.x));
        rodGuideB.setAttribute("cy", fmt(curve.guideB.y));
      }
      if (rodGuideC) {
        rodGuideC.setAttribute("cx", fmt(curve.guideC.x));
        rodGuideC.setAttribute("cy", fmt(curve.guideC.y));
      }
      if (rodGuideTip) {
        rodGuideTip.setAttribute("cx", fmt(curve.guideTip.x));
        rodGuideTip.setAttribute("cy", fmt(curve.guideTip.y));
      }
      if (rodBobberStem) {
        rodBobberStem.setAttribute("x", fmt(bobberX - 10));
        rodBobberStem.setAttribute("y", fmt(effectiveLineBottomY - 15));
        rodBobberStem.setAttribute("width", "20");
        rodBobberStem.setAttribute("height", "48");
        rodBobberStem.setAttribute("rx", "10");
      }

      if (rodBobberClipShape) {
        rodBobberClipShape.setAttribute("cx", fmt(bobberX));
        rodBobberClipShape.setAttribute("cy", fmt(effectiveBobberY));
        rodBobberClipShape.setAttribute("rx", fmt(bobberRx));
        rodBobberClipShape.setAttribute("ry", fmt(bobberRy));
      }
      if (rodBobberMain) {
        rodBobberMain.setAttribute("cx", fmt(bobberX));
        rodBobberMain.setAttribute("cy", fmt(effectiveBobberY));
        rodBobberMain.setAttribute("rx", fmt(bobberRx));
        rodBobberMain.setAttribute("ry", fmt(bobberRy));
      }
      if (rodBobberBand) {
        const bandHeight = Math.max(14, bobberRy * 0.41);
        const bandWidth = bobberRx * 2.28;
        rodBobberBand.setAttribute("x", fmt(bobberX - bandWidth / 2));
        rodBobberBand.setAttribute("y", fmt(effectiveBobberY - bandHeight * 0.75));
        rodBobberBand.setAttribute("width", fmt(bandWidth));
        rodBobberBand.setAttribute("height", fmt(bandHeight));
        rodBobberBand.setAttribute("rx", fmt(bandHeight / 2));
      }
      if (rodBobberBottom) {
        const leftX = bobberX - bobberRx * 1.1;
        const rightX = bobberX + bobberRx * 1.1;
        const topY = effectiveBobberY + bobberRy * 0.51;
        const c1X = bobberX - bobberRx * 0.52;
        const c2X = bobberX + bobberRx * 0.4;
        const lowY = effectiveBobberY + bobberRy * 0.84;
        const rightTopY = effectiveBobberY + bobberRy * 0.46;
        const bottomY = effectiveBobberY + bobberRy * 1.15;
        rodBobberBottom.setAttribute("d", [
          `M${fmt(leftX)} ${fmt(topY)}`,
          `C${fmt(c1X)} ${fmt(lowY)} ${fmt(c2X)} ${fmt(lowY)} ${fmt(rightX)} ${fmt(rightTopY)}`,
          `L${fmt(rightX)} ${fmt(bottomY)}`,
          `L${fmt(leftX)} ${fmt(bottomY)} Z`
        ].join(" "));
      }
      if (rodBobberHighlight) {
        const highlightX = bobberX - bobberRx * 0.46;
        const highlightY = effectiveBobberY - bobberRy * 0.57;
        rodBobberHighlight.setAttribute("cx", fmt(highlightX));
        rodBobberHighlight.setAttribute("cy", fmt(highlightY));
        rodBobberHighlight.setAttribute("rx", fmt(bobberRx * 0.25));
        rodBobberHighlight.setAttribute("ry", fmt(bobberRy * 0.35));
        rodBobberHighlight.setAttribute("transform", `rotate(38 ${fmt(highlightX)} ${fmt(highlightY)})`);
      }
      const waterSpreadT = smooth01((motion.effectiveBend + 1) / 2);
      const waterSurfaceY = bobberY + 25;
      const lowerWaterY = bobberY + 74;
      const rippleMainRx = lerp(122, 226, waterSpreadT);
      const rippleMainRy = lerp(26, 52, waterSpreadT);
      const rippleMidRx = lerp(52, 118, waterSpreadT);
      const rippleMidRy = lerp(14, 29, waterSpreadT);
      const rippleLowRx = lerp(40, 96, waterSpreadT);
      const rippleLowRy = lerp(12, 28, waterSpreadT);
      if (rodWaterRippleMain) {
        rodWaterRippleMain.setAttribute("cx", fmt(bobberX - 30));
        rodWaterRippleMain.setAttribute("cy", fmt(waterSurfaceY));
        rodWaterRippleMain.setAttribute("rx", fmt(rippleMainRx));
        rodWaterRippleMain.setAttribute("ry", fmt(rippleMainRy));
        rodWaterRippleMain.setAttribute("opacity", fmt(0.72 + waterSpreadT * 0.23));
      }
      if (rodWaterRippleMid) {
        rodWaterRippleMid.setAttribute("cx", fmt(bobberX - 5));
        rodWaterRippleMid.setAttribute("cy", fmt(waterSurfaceY));
        rodWaterRippleMid.setAttribute("rx", fmt(rippleMidRx));
        rodWaterRippleMid.setAttribute("ry", fmt(rippleMidRy));
        rodWaterRippleMid.setAttribute("opacity", fmt(0.38 + waterSpreadT * 0.3));
      }
      if (rodWaterRippleLow) {
        rodWaterRippleLow.setAttribute("cx", fmt(bobberX + 12));
        rodWaterRippleLow.setAttribute("cy", fmt(lowerWaterY));
        rodWaterRippleLow.setAttribute("rx", fmt(rippleLowRx));
        rodWaterRippleLow.setAttribute("ry", fmt(rippleLowRy));
        rodWaterRippleLow.setAttribute("opacity", fmt(0.44 + waterSpreadT * 0.42));
      }

      rodHandleXOut.textContent = fmt(handleX);
      rodHandleYOut.textContent = fmt(handleY);
      rodHandleRotateOut.textContent = fmt(handleRotateValue);
      rodLineXOut.textContent = fmt(lineX);
      rodLineTopYOut.textContent = fmt(lineTopY);
      rodLineBottomYOut.textContent = fmt(lineBottomY);
      rodBendOut.textContent = fmt(bend);
      rodBendFocusOut.textContent = fmt(bendFocus);
      rodMotionPhaseOut.textContent = fmt(motion.phase);
      rodMotionSpeedOut.textContent = fmt(motion.speed);
      rodBendSwingOut.textContent = fmt(motion.swing);
      rodTipTravelOut.textContent = fmt(motion.tipTravel);
      rodBobberTravelOut.textContent = fmt(motion.bobberTravel);
      biteMotionPhaseOut.textContent = fmt(motion.bite.phase);
      biteMotionSpeedOut.textContent = fmt(motion.bite.speed);
      biteStrengthOut.textContent = fmt(motion.bite.strength);
      biteFishLungeOut.textContent = fmt(motion.bite.fishLunge);
      biteBobberDipOut.textContent = fmt(motion.bite.bobberDip);
      biteRodKickOut.textContent = fmt(motion.bite.rodKick);
      rodBobberXOut.textContent = fmt(bobberX);
      rodBobberYOut.textContent = fmt(bobberY);
      rodBobberRxOut.textContent = fmt(bobberRx);
      rodBobberRyOut.textContent = fmt(bobberRy);

      return {
        handleX,
        handleY,
        handleRotate: handleRotateValue,
        lineX,
        lineTopY,
        lineBottomY,
        bend,
        bendFocus,
        motionPhase: motion.phase,
        motionSpeed: motion.speed,
        bendSwing: motion.swing,
        tipTravel: motion.tipTravel,
        bobberTravel: motion.bobberTravel,
        bitePhase: motion.bite.phase,
        biteStrength: motion.bite.strength,
        bitePulse: motion.bite.pulse,
        biteFirstPulse: motion.bite.firstPulse,
        biteSecondPulse: motion.bite.secondPulse,
        biteSwimLoopPhase: motion.bite.swimLoopPhase,
        biteApproach: motion.bite.approach,
        biteEscape: motion.bite.escape,
        biteStage: motion.bite.stage,
        biteBobberDy: motion.bite.bobberDy,
        biteRodPull: motion.bite.rodPull,
        curveBend: motion.curveBend,
        effectiveBend: motion.effectiveBend,
        effectiveLineTopY,
        effectiveLineBottomY,
        effectiveBobberY,
        effectiveBendFocus,
        tipDy: motion.tipDy,
        bobberDy: motion.bobberDy,
        waterSpreadT,
        waterSurfaceY,
        rodPath: cubicPath(curve.start, curve.c1, curve.c2, curve.tip),
        rodHighlightPath: rodHighlightPath(curve),
        bobberX,
        bobberY,
        bobberRx,
        bobberRy
      };
    }

    function updateAll() {
      const story = storyMotionState();
      storyMotionPhaseOut.textContent = fmt(story.phase);
      storyMotionSpeedOut.textContent = fmt(story.speed);
      const d = updateBody();
      const face = updateHeadFace(story);
      const leftHand = updateLeftHand();
      const hand = updateRightHand();
      const backCards = updateBackCards();
      const fishingGear = updateFishingGear();
      const fishTerminal = updateFishTerminal();
      const codeTerminal = updateCodeTerminal();
      const chatTerminal = updateChatTerminal();
      const rod = updateRodDetails();
      const thinkingSticker = updateThinkingSticker(story);
      readout.textContent = [
        `storyKeyframe: ${activeStoryKeyframeName}`,
        `storyPhase: ${fmt(story.phase)}`,
        `storyTime: ${fmt(story.time)}`,
        `storyStage: ${story.stage}`,
        `storyThinkingOpacity: ${fmt(thinkingSticker.opacity)}`,
        `thinkingHandX: ${fmt(Number(thinkingHandX.value))}`,
        `thinkingHandY: ${fmt(Number(thinkingHandY.value))}`,
        `thinkingHandScale: ${fmt(Number(thinkingHandScale.value))}`,
        `thinkingHandRotate: ${fmt(Number(thinkingHandRotate.value))}`,
        `thinkingHandOpacity: ${fmt(Number(thinkingHandOpacity.value))}`,
        `storyBitePhase: ${fmt(story.bitePhase)}`,
        `bodyLeftBulge: ${fmt(Number(leftBulge.value))}`,
        `bodyLowerWidth: ${fmt(Number(bodyWidth.value))}`,
        `bodyBottomDrop: ${fmt(Number(bottomDrop.value))}`,
        `headX: ${fmt(face.x)}`,
        `headY: ${fmt(face.y)}`,
        `headRotate: ${fmt(face.rotate)}`,
        `headYaw: ${fmt(face.yaw)}`,
        `eyesOpen: ${fmt(face.open)}`,
        `glassesY: ${fmt(face.glassesOffsetY)}`,
        `glassesRotate: ${fmt(face.glassesAngle)}`,
        `mouthInset: ${fmt(face.mouthInset)}`,
        `mouthFocusInset: ${fmt(Number(mouthFocusInset.value))}`,
        `mouthThinkingMin: ${fmt(Number(mouthThinkingMin.value))}`,
        `mouthThinkingMax: ${fmt(Number(mouthThinkingMax.value))}`,
        `mouthHappyInset: ${fmt(Number(mouthHappyInset.value))}`,
        `mouthHappyOpen: ${fmt(face.mouthHappyOpen)}`,
        `mouthHappyPulse: ${fmt(face.mouthHappyPulse)}`,
        `browFocus: ${fmt(face.brow.focus)}`,
        `browThinking: ${fmt(face.brow.thinking)}`,
        `browHappy: ${fmt(face.brow.happy)}`,
        `browHappyLift: ${fmt(Number(browHappyLift.value))}`,
        `leftHandRootX: ${fmt(leftHand.x)}`,
        `leftHandRootY: ${fmt(leftHand.y)}`,
        `leftHandScale: ${fmt(leftHand.scale)}`,
        `leftHandThickness: ${fmt(leftHand.thickness)}`,
        `leftHandRotate: ${fmt(leftHand.rotate)}`,
        `leftHandElbowAngle: ${fmt(leftHand.elbowAngle)}`,
        `leftHandElbowOut: ${fmt(leftHand.elbowOut)}`,
        `leftHandElbowMarkerX: ${fmt(leftHand.elbowX)}`,
        `leftHandElbowMarkerY: ${fmt(leftHand.elbowY)}`,
        `leftHandTipX: ${fmt(leftHand.tipX)}`,
        `leftHandTipY: ${fmt(leftHand.tipY)}`,
        `leftHandOpacity: ${fmt(leftHand.opacity)}`,
        `leftHandIdleBack: ${fmt(leftHand.idleBack)}`,
        `leftHandSource: #left-hand from hamster-flat-layered-v18-noodle-hands.svg`,
        `rightHandCenterX: ${fmt(hand.x)}`,
        `rightHandCenterY: ${fmt(hand.y)}`,
        `rightHandScale: ${fmt(hand.scale)}`,
        `rightHandRotate: ${fmt(hand.rotate)}`,
        `rightHandOpacity: ${fmt(hand.opacity)}`,
        `rightHandIdleBack: ${fmt(hand.idleBack)}`,
        `rightHandImage: reference/cutouts/right-hand-arm-no-rod-toned-v1.png`,
        `backCardsCenterX: ${fmt(backCards.x)}`,
        `backCardsCenterY: ${fmt(backCards.y)}`,
        `backCardsScale: ${fmt(backCards.scale)}`,
        `backCardsRotate: ${fmt(backCards.rotate)}`,
        `backCardsOpacity: ${fmt(backCards.opacity)}`,
        `backCardsImage: reference/hamster_back_three_cards.svg`,
        `fishingGearCenterX: ${fmt(fishingGear.x)}`,
        `fishingGearCenterY: ${fmt(fishingGear.y)}`,
        `fishingGearScale: ${fmt(fishingGear.scale)}`,
        `fishingGearRotate: ${fmt(fishingGear.rotate)}`,
        `fishingGearOpacity: ${fmt(fishingGear.opacity)}`,
        `fishingGearSource: reference/fishing_rod_bobber_water.svg`,
        `fishTerminalCenterX: ${fmt(fishTerminal.x)}`,
        `fishTerminalCenterY: ${fmt(fishTerminal.y)}`,
        `fishTerminalScale: ${fmt(fishTerminal.scale)}`,
        `fishTerminalRotate: ${fmt(fishTerminal.rotate)}`,
        `fishTerminalOpacity: ${fmt(fishTerminal.opacity)}`,
        `fishTerminalPhase: ${fmt(fishTerminal.phase)}`,
        `fishTerminalSpeed: ${fmt(fishTerminal.speed)}`,
        `fishTerminalFloat: ${fmt(fishTerminal.floatAmount)}`,
        `fishTerminalBreath: ${fmt(fishTerminal.breathAmount)}`,
        `fishTerminalSway: ${fmt(fishTerminal.swayAmount)}`,
        `fishSwim: ${fmt(fishTerminal.swim)}`,
        `fishMinX: ${fmt(fishTerminal.fishMinX)}`,
        `fishMaxX: ${fmt(fishTerminal.fishMaxX)}`,
        `fishBaseY: ${fmt(fishTerminal.fishBaseY)}`,
        `fishYRange: ${fmt(fishTerminal.fishYRange)}`,
        `waterSpread: ${fmt(fishTerminal.waterSpread)}`,
        `fishTerminalSource: reference/hamster_back_three_cards.svg#water-fishing-card`,
        `codeTerminalCenterX: ${fmt(codeTerminal.x)}`,
        `codeTerminalCenterY: ${fmt(codeTerminal.y)}`,
        `codeTerminalScale: ${fmt(codeTerminal.scale)}`,
        `codeTerminalRotate: ${fmt(codeTerminal.rotate)}`,
        `codeTerminalOpacity: ${fmt(codeTerminal.opacity)}`,
        `codeTerminalSource: reference/hamster_back_three_cards.svg#code-editor-card`,
        `chatTerminalCenterX: ${fmt(chatTerminal.x)}`,
        `chatTerminalCenterY: ${fmt(chatTerminal.y)}`,
        `chatTerminalScale: ${fmt(chatTerminal.scale)}`,
        `chatTerminalRotate: ${fmt(chatTerminal.rotate)}`,
