        `chatTerminalSource: reference/hamster_back_three_cards.svg#chat-card`,
        `rodHandleX: ${fmt(rod.handleX)}`,
        `rodHandleY: ${fmt(rod.handleY)}`,
        `rodHandleRotate: ${fmt(rod.handleRotate)}`,
        `rodLineX: ${fmt(rod.lineX)}`,
        `rodLineTopY: ${fmt(rod.lineTopY)}`,
        `rodLineBottomY: ${fmt(rod.lineBottomY)}`,
        `rodBend: ${fmt(rod.bend)}`,
        `rodBendFocus: ${fmt(rod.bendFocus)}`,
        `rodMotionPhase: ${fmt(rod.motionPhase)}`,
        `rodMotionSpeed: ${fmt(rod.motionSpeed)}`,
        `rodBendSwing: ${fmt(rod.bendSwing)}`,
        `rodTipTravel: ${fmt(rod.tipTravel)}`,
        `rodBobberTravel: ${fmt(rod.bobberTravel)}`,
        `bitePhase: ${fmt(rod.bitePhase)}`,
        `biteStrength: ${fmt(rod.biteStrength)}`,
