        `biteEscape: ${fmt(rod.biteEscape)}`,
        `biteStage: ${rod.biteStage}`,
        `biteBobberDy: ${fmt(rod.biteBobberDy)}`,
        `biteRodPull: ${fmt(rod.biteRodPull)}`,
