    function updateGuide() {
      if (!guide) return;
      guide.style.display = showGuide.checked ? "" : "none";
    }

    storyMotionPhase.value = EXPORT_STORY_PHASE_START.toFixed(4);
    storyMotionSpeed.value = "1";
    applyStoryMotionToInputs();
    updateKeyframeSelection();
    updateAll();
    updateGuide();
    setFishTerminalPlaying(false);
    setRodMotionPlaying(false);
    setBiteMotionPlaying(false);

    function replayExportStory() {
      storyMotionPhase.value = EXPORT_STORY_PHASE_START.toFixed(4);
      storyMotionLastTs = performance.now();
      applyStoryMotionToInputs();
      updateAll();
      setStoryMotionPlaying(true);
    }

    function setExportStoryProgress(progress) {
      const p = clamp(Number(progress) || 0, 0, 1);
      storyMotionPhase.value = (EXPORT_STORY_PHASE_START + p * EXPORT_STORY_PHASE_WRAP_SPAN).toFixed(4);
      applyStoryMotionToInputs();
      updateAll();
    }

    window.__cloudlingWorking3Session = {
      play: () => setStoryMotionPlaying(true),
      pause: () => setStoryMotionPlaying(false),
      replay: replayExportStory,
      setProgress: setExportStoryProgress,
      snapshot: () => ({
        phase: Number(storyMotionPhase.value),
        startPhase: EXPORT_STORY_PHASE_START,
        variant: "full"
      })
    };
    window.__cloudlingReplayWorking3Session = replayExportStory;
    window.__cloudlingSetWorking3SessionProgress = setExportStoryProgress;
    window.__clawdSetLowPowerPaused = (paused) => {
      if (paused) setStoryMotionPlaying(false);
      else setStoryMotionPlaying(true);
    };

    const reduceMotion = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (!reduceMotion) setStoryMotionPlaying(true);
